                                    <div className="pdf-recent-title">{name}</div>
                                </li>
                            )
                        })}
                    </ul>
                )}
            </div>
        </div>
    )
}

import type { FC, ChangeEvent, FormEvent, MouseEvent as ReactMouseEvent } from 'react'
import { useEffect, useRef, useState } from 'react'
import './PromptSettingsDialog.css'
import { emptyPromptSettings, type PromptRole } from '../modules/ai/promptSettings'
import { usePromptSettingsPersistence } from '../hooks/usePromptSettingsPersistence'
import { usePromptSettingsState, type PromptRoleDraft } from '../hooks/usePromptSettingsState'
import { onNativePaste } from '../modules/platform/clipboardEvents'
import { FieldGroup } from './FieldGroup'

export type PromptSettingsDialogProps = {
  open: boolean
  onClose: () => void
}

export const PromptSettingsDialog: FC<PromptSettingsDialogProps> = ({ open, onClose }) => {
  const { load, save } = usePromptSettingsPersistence()
  const {
    settings,
    setSettings,
    draft,
    expandedId,
    setExpandedId,
    error,
    setError,
    setInitialSnapshot,
    defaultRole,
    updateDraftField,
    resetDraft,
    addOrUpdateRoleFromDraft,
    deleteRole,
    moveRole,
    setDefaultRole,
    editRoleIntoDraft,
    applyInitialSnapshot,
    updateInitialSnapshot,
  } = usePromptSettingsState(emptyPromptSettings)

  const nameInputRef = useRef<HTMLInputElement | null>(null)
  const descInputRef = useRef<HTMLInputElement | null>(null)
  const promptTextareaRef = useRef<HTMLTextAreaElement | null>(null)
  const [draggingRoleId, setDraggingRoleId] = useState<string | null>(null)
  const [previewTargetId, setPreviewTargetId] = useState<string | null>(null)
  const rolesListRef = useRef<HTMLDivElement | null>(null)

  // 拖拽排序时容器上下的安全范围（像素），用于允许在列表附近一点的位置松手
  const DRAG_SAFE_MARGIN = 48

  useEffect(() => {
    if (!open) return

    let disposed = false

    const doLoad = async () => {
      const state = await load()
      if (disposed) return
      setSettings(state)
      setInitialSnapshot(state)
    }

    void doLoad()

    return () => {
      disposed = true
    }
  }, [open, load, setSettings, setInitialSnapshot])

  // 支持在 Prompt Settings 窗口输入框中使用 Cmd/Ctrl+V 粘贴
  useEffect(() => {
    if (!open) return

    const unPaste = onNativePaste((text) => {
      if (!text) return
      if (typeof document === 'undefined') return

      const active = document.activeElement as HTMLElement | null
      if (!active) return

      let el: HTMLInputElement | HTMLTextAreaElement | null = null
      let field: keyof PromptRoleDraft | null = null

      if (active === nameInputRef.current) {
        el = active as HTMLInputElement
        field = 'name'
      } else if (active === descInputRef.current) {
        el = active as HTMLInputElement
        field = 'description'
      } else if (active === promptTextareaRef.current) {
        el = active as HTMLTextAreaElement
        field = 'prompt'
      } else {
        return
      }

      const start = el.selectionStart ?? el.value.length
      const end = el.selectionEnd ?? el.value.length
      const value = el.value
      const next = value.slice(0, start) + text + value.slice(end)

      el.value = next
      if (field) {
        updateDraftField(field, next)
      }

      const pos = start + text.length
      el.setSelectionRange(pos, pos)
    })

    return () => {
      unPaste()
    }
  }, [open, updateDraftField])

  const handleRoleMouseDown = (roleId: string) => (e: ReactMouseEvent<HTMLDivElement>) => {
    e.preventDefault()
    e.stopPropagation()

    setDraggingRoleId(roleId)

    const container = rolesListRef.current
    if (!container) return

    const items = Array.from(container.querySelectorAll<HTMLDivElement>('.prompt-role-item'))
    if (!items.length) return

    const handleMouseMove = (moveEvent: MouseEvent) => {
      moveEvent.preventDefault()

      const mouseY = moveEvent.clientY
      const containerRect = container.getBoundingClientRect()

      const insideExtendedContainer =
        mouseY >= containerRect.top - DRAG_SAFE_MARGIN &&
        mouseY <= containerRect.bottom + DRAG_SAFE_MARGIN

      if (!insideExtendedContainer) {
        setPreviewTargetId(null)
        return
      }

      let nearestIndex = 0
      let nearestDistance = Number.POSITIVE_INFINITY

      items.forEach((el, index) => {
        const rect = el.getBoundingClientRect()
        const centerY = (rect.top + rect.bottom) / 2
        const dist = Math.abs(centerY - mouseY)
        if (dist < nearestDistance) {
          nearestDistance = dist
          nearestIndex = index
        }
      })

      const roles = settings.roles
      const targetRole = roles[nearestIndex]
      setPreviewTargetId(targetRole?.id ?? null)
    }

    const handleMouseUp = (upEvent: MouseEvent) => {
      window.removeEventListener('mousemove', handleMouseMove)
      window.removeEventListener('mouseup', handleMouseUp)

      const sourceId = roleId
      const containerRect = container.getBoundingClientRect()
      const mouseY = upEvent.clientY

      const insideExtendedContainer =
        mouseY >= containerRect.top - DRAG_SAFE_MARGIN &&
        mouseY <= containerRect.bottom + DRAG_SAFE_MARGIN

      setDraggingRoleId(null)
      setPreviewTargetId(null)

      if (!sourceId || !insideExtendedContainer) {
        return
      }

      let nearestIndex = 0
      let nearestDistance = Number.POSITIVE_INFINITY

      items.forEach((el, index) => {
        const rect = el.getBoundingClientRect()
        const centerY = (rect.top + rect.bottom) / 2
        const dist = Math.abs(centerY - mouseY)
        if (dist < nearestDistance) {
          nearestDistance = dist
          nearestIndex = index
        }
      })

      const roles = settings.roles
      const fromIndex = roles.findIndex((r) => r.id === sourceId)
      const targetRole = roles[nearestIndex]

      if (!targetRole || fromIndex === -1 || targetRole.id === sourceId) {
        return
      }

      moveRole(sourceId, targetRole.id)
    }

    window.addEventListener('mousemove', handleMouseMove)
    window.addEventListener('mouseup', handleMouseUp)
  }

  if (!open) return null

  const handleDraftChange = (field: keyof PromptRoleDraft) => (
    e: ChangeEvent<HTMLInputElement | HTMLTextAreaElement>,
  ) => {
    const value = e.target.value
    updateDraftField(field, value)
  }

  const handleResetDraft = () => {
    resetDraft()
  }

  const handleAddRole = (e: FormEvent) => {
    e.preventDefault()
    void addOrUpdateRoleFromDraft()
    // 添加后立即重置展开状态，确保新角色不展开
    setExpandedId(null)
  }

  const handleEditRole = (role: PromptRole) => {
    editRoleIntoDraft(role)
  }

  const handleDeleteRole = (id: string) => {
    deleteRole(id)
    if (expandedId === id) {
      resetDraft()
    }
  }

  const handleSetDefaultRole = (id: string) => {
    setDefaultRole(id)
  }

  const handleCancel = () => {
    applyInitialSnapshot()
    onClose()
  }

  const handleSave = async () => {
    const stateToSave = settings

    const ok = await save(stateToSave)
    if (!ok) {
      setError('Failed to save prompt settings. Please try again.')
      return
    }

    setSettings(stateToSave)
    updateInitialSnapshot(stateToSave)
    resetDraft()
    setError(null)
    onClose()
  }

  const ROLE_FORM_FIELDS: { key: keyof PromptRoleDraft; label: string; type: 'text' | 'textarea'; placeholder: string; ref: any }[] = [
    { key: 'name', label: 'Role Name', type: 'text', placeholder: 'e.g. Expert Markdown Editor', ref: nameInputRef },
    { key: 'description', label: 'Paramters (optional)', type: 'text', placeholder: 'Short description shown in the list', ref: descInputRef },
    { key: 'prompt', label: 'Prompt', type: 'textarea', placeholder: 'You are an expert Markdown editor...', ref: promptTextareaRef },
  ]

  return (
    <div className="modal-backdrop">
      <div className="modal modal-prompt-settings">
        <div className="modal-title">Prompt Settings</div>
        <div className="modal-content prompt-settings-body">
          <div className="prompt-settings-column-left">
            <form onSubmit={handleAddRole} className="prompt-settings-form">
              {ROLE_FORM_FIELDS.map((field) => (
                <FieldGroup key={field.key} label={field.label}>
                  {field.type === 'textarea' ? (
                    <textarea
                      className="field-textarea"
                      rows={1}
                      value={draft[field.key]}
                      onChange={handleDraftChange(field.key)}
                      placeholder={field.placeholder}
                      ref={field.ref}
                    />
                  ) : (
                    <input
                      className="field-input"
                      type="text"
                      value={draft[field.key]}
                      onChange={handleDraftChange(field.key)}
                      placeholder={field.placeholder}
                      ref={field.ref}
                    />
                  )}
                </FieldGroup>
              ))}

              {error && <div className="form-error">{error}</div>}

              <div className="prompt-settings-form-actions">
                <button type="button" className="ghost" onClick={handleResetDraft}>
                  Reset Draft
                </button>
                <button type="submit" className="ghost primary">
                  Add
                </button>
              </div>
            </form>
          </div>

          <div className="prompt-settings-column-right">
            <div className="providers-header">Saved Roles</div>
            {settings.roles.length === 0 ? (
              <div className="providers-empty">No roles configured yet.</div>
            ) : (
              <div
                className="providers-list prompt-roles-list"
                ref={rolesListRef}
              >
                {settings.roles.map((r) => {
                  const isExpanded = expandedId === r.id
                  const isDefault = settings.defaultRoleId === r.id
                  const isDragging = draggingRoleId === r.id
                  const isInsertPreview = previewTargetId === r.id
                  const isBuiltin = r.builtin
                  const itemClassName = `provider-item prompt-role-item${isDragging ? ' prompt-role-item-dragging' : ''
                    }${isInsertPreview ? ' prompt-role-item-insert-target' : ''}${isBuiltin ? ' prompt-role-item-builtin' : ''
                    }`

                  return (
                    <div
                      key={r.id}
                      className={itemClassName}
                    >
                      <div
                        className="provider-row"
                        onClick={() => {
                          if (isBuiltin) return
                          setExpandedId(isExpanded ? null : r.id)
                        }}
                      >
                        {!isBuiltin && (
                          <div
                            className="provider-drag-handle"
                            onMouseDown={handleRoleMouseDown(r.id)}
                            onClick={(e) => e.stopPropagation()}
                            aria-label="Drag to reorder"
                            role="button"
                          >
                            ⋮⋮
                          </div>
                        )}
                        <button
                          type="button"
                          className="provider-default-dot"
                          onClick={(e) => {
                            e.stopPropagation()
                            handleSetDefaultRole(r.id)
                          }}
                          aria-pressed={isDefault}
                        >
                          {isDefault ? '●' : '○'}
                        </button>
                        <div className="provider-main">
                          <div className="provider-name">{r.name}</div>
                          {r.description && (
                            <div className="provider-sub">{r.description}</div>
                          )}
                        </div>
                        <button
                          type="button"
                          className="provider-toggle"
                          aria-label={isExpanded ? 'Collapse' : 'Expand'}
                        >
                          {isExpanded ? '▼' : '▶'}
                        </button>
                      </div>

                      {isExpanded && !isBuiltin && (
                        <div className="provider-details">

                          <div className="provider-detail-row">Prompt Preview:</div>
                          <div className="prompt-preview">
                            {(() => {
                              const lines = r.prompt.split(/\r?\n/)
                              const previewLines = lines.slice(0, 5)
                              let previewText = previewLines.join('\n')

                              // 如果内容超过5行或者总字符数超过300，添加省略号
                              if (lines.length > 5 || previewText.length > 150) {
                                // 确保最后显示省略号
                                if (previewText.length > 150) {
                                  previewText = previewText.substring(0, 147) + '...'
                                } else {
                                  previewText += '...'
                                }
                              }

                              return previewText
                            })()}
                          </div>
                          <div className="provider-actions">
                            {!isBuiltin && (
                              <>
                                <button type="button" className="ghost" onClick={() => handleEditRole(r)}>
                                  Edit Role
                                </button>
                                <button
                                  type="button"
                                  className="ghost danger"
                                  onClick={() => handleDeleteRole(r.id)}
                                >
                                  Delete Role
                                </button>
                              </>
                            )}
                          </div>
                        </div>
                      )}
                    </div>
                  )
                })}
              </div>
            )}

            {defaultRole && (
              <div className="default-summary">
                Default prompt role: {defaultRole.name}
              </div>
            )}
          </div>
        </div>

        <div className="modal-actions">
          <button className="ghost" type="button" onClick={handleCancel}>
            Cancel
          </button>
          <button className="ghost primary" type="button" onClick={handleSave}>
            Save
          </button>
        </div>
      </div>
    </div>
  )
}

import { useEffect, useRef, useState } from 'react'
import type { FileTreeNode } from '../domain/sidebarTree'
import { FileContextMenu } from './FileContextMenu'
import './Sidebar.css'

export type StandaloneFileItem = {
  path: string
  name: string
}

export type SidebarContextTargetKind = 'standalone-file' | 'folder-root' | 'tree-file' | 'tree-dir'

export type SidebarContextAction = 'open' | 'remove' | 'delete' | 'open-terminal' | 'open-in-file-manager'

export type SidebarContextActionPayload = {
  path: string
  kind: SidebarContextTargetKind
  action: SidebarContextAction
}

export type SidebarProps = {
  standaloneFiles: StandaloneFileItem[]
  folderRoots: string[]
  treesByRoot: Record<string, FileTreeNode[]>
  expanded: Record<string, boolean>
  onToggle: (path: string) => void
  onFileClick: (path: string) => void
  onDirClick?: (path: string) => void  // 文件夹点击回调（用于选中文件夹）
  onContextAction?: (payload: SidebarContextActionPayload) => void
  /** 顶部工具栏：在当前文件夹中新建文件 */
  onToolbarNewFileInCurrentFolder?: () => void
  /** 顶部工具栏：在当前文件夹中新建子文件夹 */
  onToolbarNewFolderInCurrentFolder?: () => void
  /** 顶部工具栏：刷新当前文件夹 */
  onToolbarRefreshCurrentFolder?: () => void
  /** 行内新建文件：当前处于命名状态的目录 */
  inlineNewFileDir?: string | null
  /** 行内新建文件：确认命名 */
  onInlineNewFileConfirm?: (name: string) => void
  /** 行内新建文件：取消命名 */
  onInlineNewFileCancel?: () => void
  /** 行内新建文件夹：当前处于命名状态的目录 */
  inlineNewFolderDir?: string | null
  /** 行内新建文件夹：确认命名 */
  onInlineNewFolderConfirm?: (name: string) => void
  /** 行内新建文件夹：取消命名 */
  onInlineNewFolderCancel?: () => void
  activePath?: string | null
  panelWidth?: number
  highlightedPaths?: string[]
  onFileVisited?: (path: string) => void
}

type TreeNodeProps = {
  node: FileTreeNode
  level: number
  expanded: Record<string, boolean>
  onToggle: (path: string) => void
  onFileClick: (path: string) => void
  onDirClick?: (path: string) => void
  activePath?: string | null
  highlightedPaths?: string[]
  onFileVisited?: (path: string) => void
  onContextMenu?: (event: any, target: { path: string; kind: SidebarContextTargetKind }) => void
  inlineNewFileDir?: string | null
  onInlineNewFileConfirm?: (name: string) => void
  onInlineNewFileCancel?: () => void
  inlineNewFolderDir?: string | null
  onInlineNewFolderConfirm?: (name: string) => void
  onInlineNewFolderCancel?: () => void
}

function TreeNode({ node, level, expanded, onToggle, onFileClick, onDirClick, activePath, highlightedPaths, onFileVisited, onContextMenu, inlineNewFileDir, onInlineNewFileConfirm, onInlineNewFileCancel, inlineNewFolderDir, onInlineNewFolderConfirm, onInlineNewFolderCancel }: TreeNodeProps) {
  const isExpanded = !!expanded[node.path]
  const isActive = activePath === node.path
  const isHighlighted = highlightedPaths?.includes(node.path.replace(/\\/g, '/')) ?? false

  const paddingLeft = 8 + level * 12

  if (node.kind === 'dir') {
    return (
      <div>
        <div
          className={`tree-row dir ${isActive ? 'active' : ''}`}
          style={{ paddingLeft }}
          onClick={() => {
            onToggle(node.path)
            onDirClick?.(node.path)
          }}
          onContextMenu={(e) => {
            if (!onContextMenu) return
            e.preventDefault()
            e.stopPropagation()
            onContextMenu(e, { path: node.path, kind: 'tree-dir' })
          }}
        >
          <span
            className={`tree-icon tree-icon-chevron ${isExpanded ? 'expanded' : 'collapsed'}`}
            aria-hidden="true"
          />
          <span className="tree-name">{node.name}</span>
        </div>
        {isExpanded && (
          <>
            {inlineNewFileDir === node.path && (
              <InlineNewFileRow
                level={level + 1}
                onConfirm={onInlineNewFileConfirm}
                onCancel={onInlineNewFileCancel}
              />
            )}
            {inlineNewFolderDir === node.path && (
              <InlineNewFileRow
                level={level + 1}
                onConfirm={onInlineNewFolderConfirm}
                onCancel={onInlineNewFolderCancel}
                isFolder={true}
              />
            )}
            {node.children?.map((child) => (
              <TreeNode
                key={child.id}
                node={child}
                level={level + 1}
                expanded={expanded}
                onToggle={onToggle}
                onFileClick={onFileClick}
                onDirClick={onDirClick}
                activePath={activePath}
                highlightedPaths={highlightedPaths}
                onFileVisited={onFileVisited}
                onContextMenu={onContextMenu}
                inlineNewFileDir={inlineNewFileDir}
                onInlineNewFileConfirm={onInlineNewFileConfirm}
                onInlineNewFileCancel={onInlineNewFileCancel}
                inlineNewFolderDir={inlineNewFolderDir}
                onInlineNewFolderConfirm={onInlineNewFolderConfirm}
                onInlineNewFolderCancel={onInlineNewFolderCancel}
              />
            ))}
          </>
        )}
      </div>
    )
  }

  const className = `tree-row file ${isActive ? 'active' : ''} ${isHighlighted ? 'highlighted' : ''}`.trim()

  return (
    <div
      className={className}
      style={{ paddingLeft }}
      onClick={() => {
        onFileClick(node.path)
        if (isHighlighted && onFileVisited) {
          onFileVisited(node.path)
        }
      }}
      onContextMenu={(e) => {
        if (!onContextMenu) return
        e.preventDefault()
        e.stopPropagation()
        onContextMenu(e, { path: node.path, kind: 'tree-file' })
      }}
    >
      <span className="tree-icon">📄</span>
      <span className="tree-name">{node.name}</span>
    </div>
  )
}

type InlineNewFileRowProps = {
  level: number
  onConfirm?: (name: string) => void
  onCancel?: () => void
  isFolder?: boolean
}

function InlineNewFileRow({ level, onConfirm, onCancel, isFolder }: InlineNewFileRowProps) {
  const inputRef = useRef<HTMLInputElement | null>(null)
  const paddingLeft = 8 + level * 12

  useEffect(() => {
    if (inputRef.current) {
      inputRef.current.focus()
      inputRef.current.select()
    }
  }, [])

  const finish = (commit: boolean, value: string) => {
    const name = value.trim()
    console.log('[Sidebar.InlineNewFileRow.finish]', { isFolder, commit, raw: value, name })
    if (!commit || !name) {
      console.log('[Sidebar.InlineNewFileRow.finish] cancel', { reason: !commit ? 'no-commit' : 'empty-name' })
      onCancel?.()
      return
    }
    console.log('[Sidebar.InlineNewFileRow.finish] confirm', { name })
    onConfirm?.(name)
  }

  const placeholder = isFolder ? 'new folder' : 'new file'
  const icon = isFolder ? '📁' : '📄'
  const rowClass = isFolder ? 'tree-row dir new-file-editing' : 'tree-row file new-file-editing'

  return (
    <div
      className={rowClass}
      style={{ paddingLeft }}
      onClick={(e) => e.stopPropagation()}
    >
      <span className="tree-icon">{icon}</span>
      <input
        ref={inputRef}
        className="tree-name-input"
        placeholder={placeholder}
        onKeyDown={(e) => {
          if (e.key === 'Enter') {
            finish(true, e.currentTarget.value)
          } else if (e.key === 'Escape') {
            finish(false, e.currentTarget.value)
          }
        }}
        onBlur={(e) => {
          finish(true, e.currentTarget.value)
        }}
      />
    </div>
  )
}


export function Sidebar({ standaloneFiles, folderRoots, treesByRoot, expanded, onToggle, onFileClick, onDirClick, onContextAction, onToolbarNewFileInCurrentFolder, onToolbarNewFolderInCurrentFolder, onToolbarRefreshCurrentFolder, inlineNewFileDir, onInlineNewFileConfirm, onInlineNewFileCancel, inlineNewFolderDir, onInlineNewFolderConfirm, onInlineNewFolderCancel, activePath, panelWidth, highlightedPaths, onFileVisited }: SidebarProps) {
  const hasStandalone = standaloneFiles.length > 0
  const hasTree = folderRoots.some((rootPath) => (treesByRoot[rootPath]?.length ?? 0) > 0)

  const [menuState, setMenuState] = useState<{
    visible: boolean
    x: number
    y: number
    target: { path: string; kind: SidebarContextTargetKind } | null
  }>({ visible: false, x: 0, y: 0, target: null })

  const closeMenu = () => setMenuState({ visible: false, x: 0, y: 0, target: null })

  const triggerContextAction = (action: SidebarContextAction) => {
    if (!menuState.visible || !menuState.target || !onContextAction) return
    onContextAction({
      path: menuState.target.path,
      kind: menuState.target.kind,
      action,
    })
    closeMenu()
  }

  const handleTreeNodeContextMenu = (event: any, target: { path: string; kind: SidebarContextTargetKind }) => {
    event.preventDefault()
    event.stopPropagation()
    setMenuState({
      visible: true,
      x: event.clientX,
      y: event.clientY,
      target,
    })
  }

  const asideStyle = panelWidth ? { width: panelWidth } : undefined

  if (!hasTree && !hasStandalone) {
    return (
      <aside
        className="sidebar"
        style={asideStyle}
        onClick={closeMenu}
        onContextMenu={(e) => {
          e.preventDefault()
          closeMenu()
        }}
      >
        <div className="sidebar-header">
          <div className="pane-title">File Browser</div>
        </div>
        <div className="sidebar-body muted small">暂无文件</div>
      </aside>
    )
  }

  return (
    <aside
      className="sidebar"
      style={asideStyle}
      onClick={closeMenu}
      onContextMenu={(e) => {
        e.preventDefault()
        closeMenu()
      }}
    >
      <div className="sidebar-header">
        <div className="pane-title">File Browser</div>
      </div>
      <div className="sidebar-body">
        {hasStandalone && (
          <section className="sidebar-section">
            <div className="sidebar-section-title">Files</div>
            <ul className="sidebar-file-list">
              {standaloneFiles.map((file) => (
                <li
                  key={file.path}
                  className={`sidebar-file-row tree-row file ${activePath === file.path ? 'active' : ''}`}
                  onClick={() => onFileClick(file.path)}
                  onContextMenu={(e) => {
                    e.preventDefault()
                    e.stopPropagation()
                    setMenuState({
                      visible: true,
                      x: e.clientX,
                      y: e.clientY,
                      target: { path: file.path, kind: 'standalone-file' },
                    })
                  }}
                  title={file.path}
                >
                  <span className="tree-icon">📄</span>
                  <span className="tree-name">{file.name}</span>
                </li>
              ))}
            </ul>
          </section>
        )}

        {hasTree && (
          <section className="sidebar-section">
            <div className="sidebar-section-header">
              <div className="sidebar-section-title">Folders</div>
              <div className="folder-section-actions">
                <button
                  type="button"
                  className="folder-action-btn icon-new-file"
                  title="在当前文件夹中新建文件"
                  onClick={(e) => {
                    e.stopPropagation()
                    e.preventDefault()
                    onToolbarNewFileInCurrentFolder?.()
                  }}
                />
                <button
                  type="button"
                  className="folder-action-btn icon-new-folder"
                  title="在当前文件夹中新建子文件夹"
                  onClick={(e) => {
                    e.stopPropagation()
                    e.preventDefault()
                    onToolbarNewFolderInCurrentFolder?.()
                  }}
                />
                <button
                  type="button"
                  className="folder-action-btn icon-refresh"
                  title="刷新当前文件夹"
                  onClick={(e) => {
                    e.stopPropagation()
                    e.preventDefault()
                    onToolbarRefreshCurrentFolder?.()
                  }}
                />
              </div>
            </div>
            {folderRoots.length > 0 && (
              <ul className="sidebar-folder-list">
                {folderRoots.map((rootPath) => {
                  const name = rootPath.split(/[/\\]/).pop() ?? rootPath
                  const isExpandedRoot = !!expanded[rootPath]
                  const isActiveRoot = activePath === rootPath
                  const children = treesByRoot[rootPath] ?? []
                  return (
                    <li key={rootPath}>
                      <div
                        className={`sidebar-folder-row ${isActiveRoot ? 'active' : ''}`}
                        onClick={() => {
                          onToggle(rootPath)
                          onDirClick?.(rootPath)
                        }}
                        onContextMenu={(e) => {
                          e.preventDefault()
                          e.stopPropagation()
                          setMenuState({
                            visible: true,
                            x: e.clientX,
                            y: e.clientY,
                            target: { path: rootPath, kind: 'folder-root' },
                          })
                        }}
                        title={rootPath}
                      >
                        <span
                          className={`tree-icon tree-icon-chevron ${isExpandedRoot ? 'expanded' : 'collapsed'}`}
                          aria-hidden="true"
                        />
                        <span className="tree-name">{name}</span>
                      </div>
                      {isExpandedRoot && (
                        <div className="sidebar-folder-children">
                          {inlineNewFileDir === rootPath && (
                            <InlineNewFileRow
                              level={1}
                              onConfirm={onInlineNewFileConfirm}
                              onCancel={onInlineNewFileCancel}
                            />
                          )}
                          {inlineNewFolderDir === rootPath && (
                            <InlineNewFileRow
                              level={1}
                              onConfirm={onInlineNewFolderConfirm}
                              onCancel={onInlineNewFolderCancel}
                              isFolder={true}
                            />
                          )}
                          {children.map((node) => (
                            <TreeNode
                              key={node.id}
                              node={node}
                              level={1}
                              expanded={expanded}
                              onToggle={onToggle}
                              onFileClick={onFileClick}
                              onDirClick={onDirClick}
                              activePath={activePath}
                              highlightedPaths={highlightedPaths}
                              onFileVisited={onFileVisited}
                              onContextMenu={handleTreeNodeContextMenu}
                              inlineNewFileDir={inlineNewFileDir}
                              onInlineNewFileConfirm={onInlineNewFileConfirm}
                              onInlineNewFileCancel={onInlineNewFileCancel}
                              inlineNewFolderDir={inlineNewFolderDir}
                              onInlineNewFolderConfirm={onInlineNewFolderConfirm}
                              onInlineNewFolderCancel={onInlineNewFolderCancel}
                            />
                          ))}
                        </div>
                      )}
                    </li>
                  )
                })}
              </ul>
            )}
          </section>
        )}
      </div>

      {menuState.visible && menuState.target && (
        <FileContextMenu
          x={menuState.x}
          y={menuState.y}
          onRequestClose={closeMenu}
          items={(() => {
            const target = menuState.target!
            const items = [
              { id: 'open', label: 'Open', onClick: () => triggerContextAction('open') },
              { id: 'open-in-file-manager', label: 'Open in File Manager', onClick: () => triggerContextAction('open-in-file-manager') },
              { id: 'open-terminal', label: 'Open in Terminal', onClick: () => triggerContextAction('open-terminal') },
            ] as { id: string; label: string; onClick: () => void }[]

            const isStandaloneFile = target.kind === 'standalone-file'
            const isFileTarget = target.kind === 'standalone-file' || target.kind === 'tree-file'
            const isTreeDir = target.kind === 'tree-dir'
            const isFolderRoot = target.kind === 'folder-root'

            if (isFileTarget || isTreeDir) {
              items.push({ id: 'delete', label: 'Delete…', onClick: () => triggerContextAction('delete') })
            }
            if (isStandaloneFile) {
              items.push({ id: 'remove', label: 'Remove from File List', onClick: () => triggerContextAction('remove') })
            }
            if (isFolderRoot) {
              items.push({ id: 'remove-folder', label: 'Remove Folder', onClick: () => triggerContextAction('remove') })
            }

            return items
          })()}
        />
      )}
    </aside>
  )
}

import { ConflictModal } from './ConflictModal'
import { ConfirmDialog } from './ConfirmDialog'
import { DocConversationHistoryDialog } from '../modules/ai/ui/DocConversationHistoryDialog'
import { GlobalMemoryDialog } from '../modules/ai/ui/GlobalMemoryDialog'
import { AiChatDialog } from '../modules/ai/ui/AiChatDialog'

export type WorkspaceDialogsProps = {
    conflictError: any
    setConflictError: (err: any) => void
    onRetrySave: () => Promise<void>
    confirmDialog: any
    setConfirmDialog: (dialog: any) => void
    quitConfirmDialog: any
    setQuitConfirmDialog: (dialog: any) => void
    aiChatMode: 'floating' | 'docked'
    aiChatOpen: boolean
    aiChatState: any
    closeAiChatDialog: () => void
    filePath: string | null
    docHistoryState: { open: boolean; docPath: string | null }
    closeDocHistoryDialog: () => void
    globalMemoryState: { open: boolean; initialTab: 'persona' | 'manage' }
    closeGlobalMemoryDialog: () => void
}

export function WorkspaceDialogs(props: WorkspaceDialogsProps) {
    const {
        conflictError,
        setConflictError,
        onRetrySave,
        confirmDialog,
        setConfirmDialog,
        quitConfirmDialog,
        setQuitConfirmDialog,
        aiChatMode,
        aiChatOpen,
        aiChatState,
        closeAiChatDialog,
        filePath,
        docHistoryState,
        closeDocHistoryDialog,
        globalMemoryState,
        closeGlobalMemoryDialog,
    } = props

    return (
        <>
            {conflictError && (
                <ConflictModal
                    error={conflictError}
                    onRetrySave={onRetrySave}
                    onCancel={() => setConflictError(null)}
                />
            )}

            {confirmDialog && (
                <ConfirmDialog
                    title={confirmDialog.title}
                    message={confirmDialog.message}
                    confirmText={confirmDialog.confirmText}
                    cancelText={confirmDialog.cancelText}
                    extraText={confirmDialog.extraText}
                    variant={confirmDialog.variant}
                    onConfirm={confirmDialog.onConfirm}
                    onExtra={confirmDialog.onExtra}
                    onCancel={() => setConfirmDialog(null)}
                />
            )}

            {quitConfirmDialog && (
                <ConfirmDialog
                    title={quitConfirmDialog.unsavedCount === 1 ? 'Save changes?' : `Save ${quitConfirmDialog.unsavedCount} files?`}
                    message="Your changes will be lost."
                    confirmText="Save All"
                    cancelText="Cancel"
                    extraText="Don't Save"
                    variant="stacked"
                    onConfirm={quitConfirmDialog.onSaveAll}
                    onExtra={quitConfirmDialog.onQuitWithoutSaving}
                    onCancel={() => setQuitConfirmDialog(null)}
                />
            )}

            {aiChatMode === 'floating' && aiChatOpen && aiChatState?.open && (
                <AiChatDialog
                    open={aiChatOpen}
                    entryMode={aiChatState.entryMode}
                    initialContext={aiChatState.initialContext}
                    onClose={closeAiChatDialog}
                    currentFilePath={filePath}
                    tabId={aiChatState.tabId}
                />
            )}

            {docHistoryState.open && docHistoryState.docPath && (
                <DocConversationHistoryDialog
                    open={docHistoryState.open}
                    docPath={docHistoryState.docPath}
                    onClose={closeDocHistoryDialog}
                />
            )}

            {globalMemoryState.open && (
                <GlobalMemoryDialog
                    open={globalMemoryState.open}
                    initialTab={globalMemoryState.initialTab}
                    onClose={closeGlobalMemoryDialog}
                />
            )}
        </>
    )
}

