  )
}

import { useCallback, useEffect, useRef, useState } from 'react'
import type { ChatEntryMode, EntryContext } from '../modules/ai/domain/chatSession'

// AI Chat localStorage keys
const STORAGE_AI_MODE = 'haomd:aiChat:mode'
const STORAGE_AI_DOCK_SIDE = 'haomd:aiChat:dockSide'
const STORAGE_AI_OPEN = 'haomd:aiChat:isOpen'
const STORAGE_AI_WIDTH_LEFT = 'haomd:aiChat:widthLeft'
const STORAGE_AI_WIDTH_RIGHT = 'haomd:aiChat:widthRight'

export type AiChatManagerOptions = {
    activeTabId: string | null
}

export function useAiChatManager({ activeTabId }: AiChatManagerOptions) {
    const [aiChatState, setAiChatState] = useState<{
        open: boolean
        entryMode: ChatEntryMode
        initialContext?: EntryContext
        tabId: string
    } | null>(null)

    const [aiChatMode, setAiChatMode] = useState<'floating' | 'docked'>('docked')
    const [aiChatOpen, setAiChatOpen] = useState(false)
    const [aiChatDockSide, setAiChatDockSide] = useState<'left' | 'right'>('right')
    const [aiChatWidthLeft, setAiChatWidthLeft] = useState(400)
    const [aiChatWidthRight, setAiChatWidthRight] = useState(400)
    const [isAiChatResizing, setIsAiChatResizing] = useState(false)

    const aiChatResizeStateRef = useRef<{ startX: number; startWidth: number } | null>(null)
    const aiChatFirstSaveRef = useRef(true)
    const aiChatPrevDockSideRef = useRef<'left' | 'right'>(aiChatDockSide)

    const aiChatWidth = aiChatDockSide === 'left' ? aiChatWidthLeft : aiChatWidthRight

    // AI Chat Persistence：使用 localStorage 记住模式 / 位置 / 打开状态 / 左右宽度
    useEffect(() => {
        try {
            if (typeof localStorage === 'undefined') return

            const storedMode = localStorage.getItem(STORAGE_AI_MODE)
            const storedDockSide = localStorage.getItem(STORAGE_AI_DOCK_SIDE)
            const storedOpen = localStorage.getItem(STORAGE_AI_OPEN)
            const storedLeft = localStorage.getItem(STORAGE_AI_WIDTH_LEFT)
            const storedRight = localStorage.getItem(STORAGE_AI_WIDTH_RIGHT)

            if (storedMode === 'floating' || storedMode === 'docked') {
                setAiChatMode(storedMode as 'floating' | 'docked')
            }
            if (storedDockSide === 'left' || storedDockSide === 'right') {
                setAiChatDockSide(storedDockSide as 'left' | 'right')
            }
            if (storedOpen != null) {
                setAiChatOpen(storedOpen === 'true')
            }
            if (storedLeft != null) {
                const w = Number(storedLeft)
                if (!Number.isNaN(w)) setAiChatWidthLeft(w)
            }
            if (storedRight != null) {
                const w = Number(storedRight)
                if (!Number.isNaN(w)) setAiChatWidthRight(w)
            }
        } catch (e) {
            console.error('Failed to load AI Chat state from localStorage', e)
        }
    }, [])

    const saveAiStore = useCallback(async () => {
        try {
            if (typeof localStorage === 'undefined') return

            localStorage.setItem(STORAGE_AI_MODE, aiChatMode)
            localStorage.setItem(STORAGE_AI_DOCK_SIDE, aiChatDockSide)
            localStorage.setItem(STORAGE_AI_OPEN, String(aiChatOpen))
            localStorage.setItem(STORAGE_AI_WIDTH_LEFT, String(aiChatWidthLeft))
            localStorage.setItem(STORAGE_AI_WIDTH_RIGHT, String(aiChatWidthRight))
        } catch (e) {
            console.error('Failed to save AI Chat state to localStorage', e)
        }
    }, [aiChatMode, aiChatDockSide, aiChatOpen, aiChatWidthLeft, aiChatWidthRight])

    useEffect(() => {
        // 首次渲染只作为初始化，不写回 localStorage，避免用默认 400 覆盖已有值
        if (aiChatFirstSaveRef.current) {
            aiChatFirstSaveRef.current = false
            return
        }
        void saveAiStore()
    }, [saveAiStore])

    // 切换 dock 侧边时，沿用当前侧的宽度到新侧，避免左右宽度不一致的跳变
    useEffect(() => {
        const prevSide = aiChatPrevDockSideRef.current
        if (prevSide === aiChatDockSide) return

        if (aiChatDockSide === 'left') {
            setAiChatWidthLeft(aiChatWidthRight)
        } else {
            setAiChatWidthRight(aiChatWidthLeft)
        }

        aiChatPrevDockSideRef.current = aiChatDockSide
    }, [aiChatDockSide, aiChatWidthLeft, aiChatWidthRight])

    useEffect(() => {
        if (!isAiChatResizing) return

        const handleMove = (e: MouseEvent) => {
            const state = aiChatResizeStateRef.current
            if (!state) return

            let delta = e.clientX - state.startX
            if (aiChatDockSide === 'right') {
                delta = -delta
            }

            let next = state.startWidth + delta
            const MIN_AI_WIDTH = 340
            const MAX_AI_WIDTH = 800

            if (next < MIN_AI_WIDTH) next = MIN_AI_WIDTH
            if (next > MAX_AI_WIDTH) next = MAX_AI_WIDTH

            if (aiChatDockSide === 'left') {
                setAiChatWidthLeft(next)
            } else {
                setAiChatWidthRight(next)
            }
        }

        const handleUp = () => {
            setIsAiChatResizing(false)
            aiChatResizeStateRef.current = null
        }

        window.addEventListener('mousemove', handleMove)
        window.addEventListener('mouseup', handleUp)

        return () => {
            window.removeEventListener('mousemove', handleMove)
            window.removeEventListener('mouseup', handleUp)
        }
    }, [isAiChatResizing, aiChatDockSide])

    const openAiChatDialog = useCallback(
        (options: { entryMode: ChatEntryMode; initialContext?: EntryContext }) => {
            const tabId = activeTabId ?? 'global'
            setAiChatOpen(true)
            setAiChatState({ open: true, tabId, ...options })
        },
        [activeTabId],
    )

    const closeAiChatDialog = useCallback(() => {
        setAiChatOpen(false)
        setAiChatState(null)
    }, [])

    const handleAiChatResizeStart = useCallback((event: any) => {
        const currentWidth = aiChatDockSide === 'left' ? aiChatWidthLeft : aiChatWidthRight
        aiChatResizeStateRef.current = { startX: event.clientX, startWidth: currentWidth }
        setIsAiChatResizing(true)
        event.preventDefault()
        event.stopPropagation()
    }, [aiChatDockSide, aiChatWidthLeft, aiChatWidthRight])

    const isAiChatActuallyOpen = aiChatOpen && !!aiChatState?.open

    useEffect(() => {
        const handleKeyDown = (e: globalThis.KeyboardEvent) => {
            const key = e.key.toLowerCase()
            const isMeta = e.metaKey || e.ctrlKey
            const isShift = e.shiftKey
            if (!isMeta || !isShift || key !== 'c') {
                return
            }

            // Shift+Command+C（或 Shift+Ctrl+C）：在打开和关闭 AI Chat 之间切换
            e.preventDefault()
            e.stopPropagation()

            if (isAiChatActuallyOpen) {
                closeAiChatDialog()
            } else {
                openAiChatDialog({ entryMode: 'chat' })
            }
        }

        window.addEventListener('keydown', handleKeyDown, true)
        return () => {
            window.removeEventListener('keydown', handleKeyDown, true)
        }
    }, [isAiChatActuallyOpen, openAiChatDialog, closeAiChatDialog])

    return {
        aiChatState,
        aiChatMode,
        setAiChatMode,
        aiChatOpen,
        aiChatDockSide,
        setAiChatDockSide,
        aiChatWidth,
        isAiChatResizing,
        openAiChatDialog,
        closeAiChatDialog,
        handleAiChatResizeStart,
        isAiChatActuallyOpen,
    }
}

import { useCallback, useState } from 'react'
import type { Result } from '../modules/files/types'

export type ConfirmState = {
  title: string
  message: string
  confirmText?: string
  cancelText?: string
  extraText?: string
  variant?: 'default' | 'stacked'
  onConfirm: () => void
  onExtra?: () => void
} | null

export type QuitConfirmState = {
  unsavedCount: number
  onSaveAll: () => void
  onQuitWithoutSaving: () => void
} | null

export function useConfirmDialog() {
  const [confirmDialog, setConfirmDialog] = useState<ConfirmState>(null)

  const showConfirm = useCallback(
    (options: Omit<NonNullable<ConfirmState>, 'onConfirm'> & { onConfirm: () => void }) => {
      setConfirmDialog({ ...options })
    },
    [],
  )

  const hideConfirm = useCallback(() => setConfirmDialog(null), [])

  return { confirmDialog, showConfirm, hideConfirm, setConfirmDialog }
}

export function useQuitConfirmDialog(options: {
  getUnsavedTabs: () => { id: string; title: string }[]
  isTauriEnv: () => boolean
  save: () => Promise<Result<unknown>>
  setActiveTab: (id: string) => void
  setStatusMessage: (msg: string) => void
}) {
  const { getUnsavedTabs, isTauriEnv, save, setActiveTab, setStatusMessage } = options
  const [quitConfirmDialog, setQuitConfirmDialog] = useState<QuitConfirmState>(null)

  const requestQuit = useCallback(() => {
    const unsavedTabs = getUnsavedTabs()

    if (unsavedTabs.length === 0) {
      if (isTauriEnv()) {
        ;(window as any).__TAURI__?.core.invoke('quit_app').catch((err: unknown) => {
          console.warn('[App] quit_app failed', err)
        })
      } else {
        window.close()
      }
      return
    }

    setQuitConfirmDialog({
      unsavedCount: unsavedTabs.length,
      onSaveAll: async () => {
        setQuitConfirmDialog(null)

        for (const tab of unsavedTabs) {
          setActiveTab(tab.id)
          await new Promise((resolve) => setTimeout(resolve, 10))
          const result = await save()
          if ((result as any)?.ok === false) {
            setStatusMessage(`保存 ${tab.title} 失败: ${(result as any)?.error?.message ?? '未知错误'}`)
            return
          }
        }

        if (isTauriEnv()) {
          ;(window as any).__TAURI__?.core.invoke('quit_app').catch((err: unknown) => {
            console.warn('[App] quit_app failed', err)
          })
        } else {
          window.close()
        }
      },
      onQuitWithoutSaving: () => {
        setQuitConfirmDialog(null)
        if (isTauriEnv()) {
          ;(window as any).__TAURI__?.core.invoke('quit_app').catch((err: unknown) => {
            console.warn('[App] quit_app failed', err)
          })
        } else {
          window.close()
        }
      },
    })
  }, [getUnsavedTabs, isTauriEnv, save, setActiveTab, setStatusMessage])

  return { quitConfirmDialog, setQuitConfirmDialog, requestQuit }
}

import { useCallback, useEffect, useRef, useState } from 'react'
import { open as openDialog, save as saveDialog } from '@tauri-apps/plugin-dialog'
import { clearRecentRemote, deleteRecentRemote, logRecentFile, readFile, writeFile } from '../modules/files/service'
import { logPdfRecent } from '../modules/pdf/pdfRecentService'
import { createAutoSaver, type AutoSaveHandle } from '../modules/files/autoSave'
import type { RecentFile, Result, ServiceError, WriteResult } from '../modules/files/types'
import { isTauriEnv } from '../modules/platform/runtime'

const DEFAULT_PATH = 'untitled.md'

const isTauri = isTauriEnv

export type SaveStatus = 'idle' | 'saving' | 'saved' | 'error' | 'conflict'

function useRecentFilesState(setStatusMessage: (msg: string) => void) {
  const [recent, setRecent] = useState<RecentFile[]>([])
  const recentHasMore = false
  const recentLoading = false
  const recentLoadedFromDisk = false

  // 前端最近文件列表 / 热缓存整体下线，仅保留「清空/删除最近」调用后端的能力
  const clearRecentAll = useCallback(async () => {
    const resp = await clearRecentRemote()
    if (!resp.ok) {
      setStatusMessage(resp.error.message)
    }
    return resp
  }, [setStatusMessage])

  const deleteRecent = useCallback(
    async (path: string) => {
      const resp = await deleteRecentRemote(path)
      if (!resp.ok) {
        setStatusMessage(resp.error.message)
      }
      return resp
    },
    [setStatusMessage],
  )

  const upsertRecentLocal = () => {}
  const reloadRecentLocal = () => {}
  const refreshRecent = async () => {}
  const loadMoreRecent = async () => {}

  return {
    recent,
    setRecent,
    recentHasMore,
    recentLoading,
    recentLoadedFromDisk,
    refreshRecent,
    loadMoreRecent,
    clearRecentAll,
    deleteRecent,
    upsertRecentLocal,
    reloadRecentLocal,
  }
}

export type FilePersistenceOptions = {
  onSaved?: (path: string) => void
}

export function useFilePersistence(markdown: string, options?: FilePersistenceOptions) {
  const [filePath, setFilePath] = useState<string>(DEFAULT_PATH)
  const pathRef = useRef<string>(DEFAULT_PATH)
  const [dirty, setDirty] = useState(false)
  const [saveStatus, setSaveStatus] = useState<SaveStatus>('idle')
  const [statusMessage, setStatusMessage] = useState('')
  const [lastSavedAt, setLastSavedAt] = useState<number | null>(null)
  const [currentHash, setCurrentHash] = useState<string | undefined>(undefined)
  const [currentMtime, setCurrentMtime] = useState<number | undefined>(undefined)
  const [conflictError, setConflictError] = useState<ServiceError | null>(null)

  const {
    recent,
    setRecent,
    recentHasMore,
    recentLoading,
    recentLoadedFromDisk,
    refreshRecent,
    loadMoreRecent,
    clearRecentAll,
    deleteRecent,
    upsertRecentLocal,
    reloadRecentLocal,
  } = useRecentFilesState(setStatusMessage)

  const saverRef = useRef<AutoSaveHandle | null>(null)

  const saveInFlightRef = useRef(false)
  const firstRenderRef = useRef(true)

  useEffect(() => {
    pathRef.current = filePath
  }, [filePath])

  const handleSave = useCallback(
    async (targetPath?: string): Promise<Result<WriteResult>> => {
      if (saveInFlightRef.current) {
        return { ok: false, error: { code: 'CANCELLED', message: '保存进行中，请稍后重试', traceId: undefined } }
      }
      saveInFlightRef.current = true
      try {
        const pathToUse = targetPath ?? pathRef.current
        const resp = await writeFile({
          path: pathToUse,
          content: markdown,
          expectedHash: currentHash,
          expectedMtime: currentMtime,
        })
        if (resp.ok) {
          // 先更新 ref，避免紧接着触发的下一次保存仍判断为“未命名”
          pathRef.current = pathToUse
          setFilePath(pathToUse)
          setDirty(false)
          setSaveStatus('saved')
          setStatusMessage('已保存')
          setCurrentHash(resp.data.hash)
          setCurrentMtime(resp.data.mtimeMs)
          setLastSavedAt(Date.now())

          // 记录最近文件：保存成功后也写入后端 recent.json 和本地热缓存
          if (isTauri()) {
            void logRecentFile(pathToUse, false)
          }
          upsertRecentLocal()

          // 通知外层：保存成功，可用于更新多标签元信息
          if (options?.onSaved) {
            options.onSaved(pathToUse)
          }
        }
        return resp
      } finally {
        saveInFlightRef.current = false
      }
    },
    [markdown, currentHash, currentMtime, upsertRecentLocal, options],
  )

  const dialogInFlightRef = useRef(false)
  const openDialogInFlightRef = useRef(false)
  const openInFlightRef = useRef(false)
  const suppressDirtyOnceRef = useRef(false)

  const hasRealPathNow = useCallback(() => pathRef.current !== DEFAULT_PATH, [])

  const saveAs = useCallback(async () => {
    // 防止重复触发导致系统对话框弹多次
    if (dialogInFlightRef.current) {
      return { ok: false as const, error: { code: 'CANCELLED', message: '已在打开保存对话框', traceId: undefined } }
    }
    dialogInFlightRef.current = true

    try {
      if (!isTauri()) {
        setSaveStatus('error')
        setStatusMessage('需在 Tauri 应用中才能弹出系统保存对话框')
        return { ok: false as const, error: { code: 'UNKNOWN', message: 'Tauri 未运行', traceId: undefined } }
      }

      setSaveStatus('saving')
      setStatusMessage('选择存储位置...')
      const suggested = pathRef.current && pathRef.current !== DEFAULT_PATH ? pathRef.current : '文稿.md'
      const chosen = await saveDialog({
        defaultPath: suggested,
        filters: [{ name: 'Markdown', extensions: ['md', 'markdown', 'mdx'] }],
      })
      if (!chosen) {
        setSaveStatus('idle')
        setStatusMessage('已取消保存')
        return { ok: false as const, error: { code: 'CANCELLED', message: '用户取消', traceId: undefined } }
      }
      setSaveStatus('saving')
      setStatusMessage('保存中...')
      const resp = await handleSave(chosen)
      if (resp.ok) {
        // 已保存
      } else if (resp.error.code === 'CONFLICT') {
        setConflictError(resp.error)
        setSaveStatus('conflict')
      } else {
        setSaveStatus('error')
        setStatusMessage(resp.error.message)
      }
      return resp
    } finally {
      dialogInFlightRef.current = false
    }
  }, [filePath, handleSave])

  const saveToPath = useCallback(async () => {
    if (!hasRealPathNow()) {
      return {
        ok: false as const,
        error: { code: 'INVALID_PATH', message: '未命名文件需先选择保存位置', traceId: undefined },
      }
    }

    setSaveStatus('saving')
    setStatusMessage('保存中...')
    const resp = await handleSave()
    if (resp.ok) {
      // 已保存
    } else if (resp.error.code === 'CONFLICT') {
      setConflictError(resp.error)
      setSaveStatus('conflict')
    } else {
      setSaveStatus('error')
      setStatusMessage(resp.error.message)
    }
    return resp
  }, [handleSave, hasRealPathNow])

  const save = useCallback(async () => {
    // 关键：这里不要依赖渲染期的 memo/state，直接读 ref，避免“刚保存完又触发保存”时判断失真
    if (hasRealPathNow()) return await saveToPath()
    return await saveAs()
  }, [hasRealPathNow, saveAs, saveToPath])

  useEffect(() => {
    saverRef.current?.cancel()
    saverRef.current = createAutoSaver({
      save: () => handleSave(),
      isDirty: () => dirty,
      enabled: filePath !== DEFAULT_PATH,
      debounceMs: 120000,
      idleMs: 120000,
      onStart: () => {
        setSaveStatus('saving')
        setStatusMessage('自动保存中...')
      },
      onSuccess: (res) => {
        setDirty(false)
        setSaveStatus('saved')
        setStatusMessage('自动保存完成')
        setCurrentHash(res.hash)
        setCurrentMtime(res.mtimeMs)
        setLastSavedAt(Date.now())
      },
      onConflict: (error) => {
        setSaveStatus('conflict')
        setConflictError(error)
        setStatusMessage(error.message)
      },
      onError: (error) => {
        setSaveStatus('error')
        setStatusMessage(error.message)
      },
    })
    return () => {
      saverRef.current?.cancel()
    }
  }, [dirty, handleSave, filePath])

  useEffect(() => {
    // 首次渲染仅用于建立依赖，不应直接把文档标记为脏
    if (firstRenderRef.current) {
      firstRenderRef.current = false
      return
    }
    if (suppressDirtyOnceRef.current) {
      suppressDirtyOnceRef.current = false
      setDirty(false)
      return
    }
    setDirty(true)
    saverRef.current?.schedule()
  }, [markdown])

  const markDirty = useCallback(() => {
    setDirty(true)
    saverRef.current?.schedule()
  }, [])

  const openFromPath = useCallback(
    async (path: string) => {
      if (openInFlightRef.current) {
        return { ok: false as const, error: { code: 'CANCELLED', message: '打开进行中，请稍后重试', traceId: undefined } }
      }
      openInFlightRef.current = true
      try {
        if (!isTauri()) {
          setSaveStatus('error')
          setStatusMessage('需在 Tauri 应用中才能打开文件')
          return { ok: false as const, error: { code: 'UNKNOWN', message: 'Tauri 未运行', traceId: undefined } }
        }

        setSaveStatus('idle')
        setStatusMessage('打开中...')
        const resp = await readFile(path)
        if (!resp.ok) {
          setSaveStatus('error')
          setStatusMessage(resp.error.message)
          return resp
        }

        const nextPath = resp.data.path
        pathRef.current = nextPath
        setFilePath(nextPath)
        setCurrentHash(resp.data.hash)
        setCurrentMtime(resp.data.mtimeMs)
        setDirty(false)
        suppressDirtyOnceRef.current = true
        setSaveStatus('idle')
        setStatusMessage('已打开')

        // 记录最近文件：后端维护完整持久化，本地维护最近 10 条热缓存
        if (isTauri()) {
          void logRecentFile(nextPath, false).then((res) => {
            if (!res.ok) {
              console.warn('[logRecentFile] openFromPath failed', res.error)
              setStatusMessage(res.error.message)
            }
          })
        }
        upsertRecentLocal()

        return resp
      } finally {
        openInFlightRef.current = false
      }
    },
    [setStatusMessage, upsertRecentLocal],
  )

  const openFile = useCallback(
    async () => {
      console.log('[openFile] called, inFlight =', openDialogInFlightRef.current)
      if (openDialogInFlightRef.current) {
        console.warn('[openFile] dialog already in flight, skip')
        return { ok: false as const, error: { code: 'CANCELLED', message: '已在打开系统对话框', traceId: undefined } }
      }
      openDialogInFlightRef.current = true
      try {
        setSaveStatus('idle')
        setStatusMessage('选择要打开的文件...')
        console.log('[openFile] before openDialog')
        const chosen = await openDialog({
          multiple: false,
          directory: false,
          filters: [
            { name: 'Markdown', extensions: ['md', 'markdown', 'mdx'] },
            { name: 'PDF', extensions: ['pdf'] },
          ],
        })
        console.log('[openFile] after openDialog, chosen =', chosen)

        if (!chosen) {
          setSaveStatus('idle')
          setStatusMessage('已取消打开')
          return { ok: false as const, error: { code: 'CANCELLED', message: '用户取消', traceId: undefined } }
        }

        const selected = Array.isArray(chosen) ? chosen[0] : chosen
        const path = String(selected)
        const isPdf = path.toLowerCase().endsWith('.pdf')

        if (isPdf) {
          console.log('[openFile] open PDF path', path)
          if (isTauri()) {
            void logRecentFile(path, false).then((res) => {
              if (!res.ok) {
                console.warn('[logRecentFile] openFile(pdf) failed', res.error)
                setStatusMessage(res.error.message)
              }
            })
            void logPdfRecent(path).catch((err) => {
              console.warn('[logPdfRecent] openFile(pdf) failed', err)
            })
          }
          // 返回最小信息，由上层根据扩展名决定如何展示（例如在 PdfViewer 中打开）
          return { ok: true as const, data: { path } }
        }

        console.log('[openFile] openFromPath', path)
        return await openFromPath(path)
      } catch (err) {
        console.error('[openFile] openDialog failed', err)
        setSaveStatus('error')
        setStatusMessage(`无法打开文件: ${String((err as any)?.message ?? err)}`)
        return { ok: false as const, error: { code: 'UNKNOWN', message: '打开失败', traceId: undefined } }
      } finally {
        openDialogInFlightRef.current = false
        console.log('[openFile] dialog done, reset inFlight')
      }
    },
    [openFromPath],
  )

  // 仅当文档「实际有内容」且存在未保存修改时，才认为需要用户确认
  const hasUnsavedChanges = useCallback(() => {
    // 完全未命名、内容为空的初始文档，不拦截 Open Folder 等操作
    if (pathRef.current === DEFAULT_PATH && (!markdown || markdown.length === 0)) {
      return false
    }
    return dirty
  }, [dirty, markdown])

  const confirmLoseChanges = useCallback(() => {
    if (!dirty) return true
    return window.confirm('存在未保存变更，确认继续？')
  }, [dirty])

  const newDocument = useCallback(() => {
    // 先重置文件元信息，避免后续保存/自动保存误判成“已有路径/可对比”
    pathRef.current = DEFAULT_PATH
    setFilePath(DEFAULT_PATH)
    setCurrentHash(undefined)
    setCurrentMtime(undefined)
    setLastSavedAt(null)
    setDirty(false)
    suppressDirtyOnceRef.current = true
    setSaveStatus('idle')
    setConflictError(null)
    setStatusMessage('新建文档')
  }, [])

  return {
    DEFAULT_PATH,
    filePath,
    setFilePath,
    dirty,
    setDirty,
    saveStatus,
    statusMessage,
    setStatusMessage,
    lastSavedAt,
    currentHash,
    currentMtime,
    conflictError,
    setConflictError,
    recent,
    recentHasMore,
    recentLoading,
    recentLoadedFromDisk,
    refreshRecent,
    loadMoreRecent,
    clearRecentAll,
    deleteRecent,
    setRecent,
    reloadRecentLocal,
    handleSave,
    save,
    saveToPath,
    saveAs,
    openFile,
    openFromPath,
    markDirty,
    hasUnsavedChanges,
    confirmLoseChanges,
    newDocument,
  }
}

import { useEffect, useState } from 'react'
import { countLines, extractChunkAroundLine } from '../modules/editor/chunkEdit'
import { getHugeDocSettings } from '../modules/settings/editorSettings'

export type HugeDocState = {
    enabled: boolean
    threshold: number
    currentChunk: {
        from: number
        to: number
        value: string
    } | null
}

const DEFAULT_HUGE_DOC_LINE_THRESHOLD = 1000
const DEFAULT_ENABLE_HUGE_DOC_LOCAL_EDIT = true
const DEFAULT_HUGE_DOC_CHUNK_CONTEXT_LINES = 200
const DEFAULT_HUGE_DOC_CHUNK_MAX_LINES = 400

export type HugeDocManagerOptions = {
    markdown: string
    activeLine: number
}

export function useHugeDocManager({ markdown, activeLine }: HugeDocManagerOptions) {
    const [hugeDocState, setHugeDocState] = useState<HugeDocState | null>(null)
    const [hugeDocEnabled, setHugeDocEnabled] = useState(DEFAULT_ENABLE_HUGE_DOC_LOCAL_EDIT)
    const [hugeDocLineThreshold, setHugeDocLineThreshold] = useState(DEFAULT_HUGE_DOC_LINE_THRESHOLD)
    const [hugeDocChunkContextLines, setHugeDocChunkContextLines] = useState(DEFAULT_HUGE_DOC_CHUNK_CONTEXT_LINES)
    const [hugeDocChunkMaxLines, setHugeDocChunkMaxLines] = useState(DEFAULT_HUGE_DOC_CHUNK_MAX_LINES)

    useEffect(() => {
        let cancelled = false
            ; (async () => {
                try {
                    const cfg = await getHugeDocSettings()
                    if (cancelled) return
                    // 关闭大文档局部编辑：始终使用整篇文档，不再按 chunk 裁剪编辑器内容
                    setHugeDocEnabled(false)
                    setHugeDocLineThreshold(cfg.lineThreshold)
                    setHugeDocChunkContextLines(cfg.chunkContextLines)
                    setHugeDocChunkMaxLines(cfg.chunkMaxLines)
                } catch (e) {
                    console.error('[useHugeDocManager] load hugeDoc settings failed, using defaults', e)
                }
            })()
        return () => {
            cancelled = true
        }
    }, [])

    // Huge doc detection & initial chunk computation（只负责开启/关闭和首次初始化，不反复重算）
    useEffect(() => {
        if (!hugeDocEnabled) {
            setHugeDocState(null)
            return
        }

        const lineCount = countLines(markdown)
        const enabled = lineCount >= hugeDocLineThreshold

        if (!enabled) {
            if (hugeDocState) {
                console.debug('[HugeDoc] disabled for current document, lineCount =', lineCount)
            }
            setHugeDocState(null)
            return
        }

        // 已经有有效 chunk，则不在这里自动重算，避免与程序性跳转互相覆盖
        if (hugeDocState?.enabled && hugeDocState.currentChunk) {
            return
        }

        try {
            const centerLine = activeLine > 0 ? activeLine : 1
            const chunk = extractChunkAroundLine(markdown, centerLine, {
                contextLines: hugeDocChunkContextLines,
                maxLines: hugeDocChunkMaxLines,
            })

            console.debug('[HugeDoc] enabled, lineCount =', lineCount, 'chunk =', {
                from: chunk.from,
                to: chunk.to,
                length: chunk.value.length,
            })

            setHugeDocState({
                enabled: true,
                threshold: hugeDocLineThreshold,
                currentChunk: chunk,
            })
        } catch (e) {
            console.error('[HugeDoc] failed to compute chunk for huge doc, fallback to normal mode', e)
            setHugeDocState(null)
        }
    }, [markdown, activeLine, hugeDocEnabled, hugeDocLineThreshold, hugeDocChunkContextLines, hugeDocChunkMaxLines, hugeDocState])

    return {
        hugeDocState,
        setHugeDocState,
        hugeDocEnabled,
        hugeDocLineThreshold,
        hugeDocChunkContextLines,
        hugeDocChunkMaxLines,
    }
}

import { useEffect, type RefObject } from 'react'
import { invoke } from '@tauri-apps/api/core'
import { EditorView } from '@codemirror/view'
import { onOpenRecentFile } from '../modules/platform/menuEvents'
import { onNativePasteImage } from '../modules/platform/clipboardEvents'
import { loadDefaultImagePathStrategyConfig, resolveImageTarget } from '../modules/images/imagePasteStrategy'
import type { EditorTab } from '../types/tabs'

export type NativeBridgeOptions = {
    activeTab: EditorTab | null
    isTauriEnv: () => boolean
    sidebar: any
    openRecentFileInNewTab: (path: string) => Promise<any>
    editorViewRef: RefObject<EditorView | null>
    filePath: string | null
    setStatusMessage: (msg: string) => void
    setConfirmDialog: (dialog: any) => void
}

export function useNativeBridge(options: NativeBridgeOptions) {
    const {
        activeTab,
        isTauriEnv,
        sidebar,
        openRecentFileInNewTab,
        editorViewRef,
        filePath,
        setStatusMessage,
        setConfirmDialog,
    } = options

    // Window Title
    useEffect(() => {
        const DEFAULT_TITLE = 'undefined.md'
        const formatWindowTitleFromTab = (tab: EditorTab | null): string => {
            if (!tab) return DEFAULT_TITLE
            const path = tab.path
            const name = path ? path.split(/[/\\]/).pop() || path : tab.title || DEFAULT_TITLE
            const prefix = tab.dirty ? '*' : ''
            return `${prefix}${name}`
        }

        const title = formatWindowTitleFromTab(activeTab)
        if (isTauriEnv()) {
            void invoke('set_title', { title }).catch(() => { })
        }
    }, [activeTab, isTauriEnv])

    // Recent Files
    useEffect(() => {
        const unlisten = onOpenRecentFile(({ path, isFolder }) => {
            if (isFolder) {
                void sidebar.openFolderAsRoot(path)
            } else {
                void openRecentFileInNewTab(path)
            }
        })
        return () => unlisten()
    }, [openRecentFileInNewTab, sidebar])

    // Paste Image
    useEffect(() => {
        const unlisten = onNativePasteImage(async () => {
            const view = editorViewRef.current
            if (!view) return

            if (typeof document !== 'undefined') {
                const active = document.activeElement
                const contains = active ? view.dom.contains(active) : false
                if (active && !contains) return
            }

            if (!filePath || filePath === 'untitled.md') {
                setConfirmDialog({
                    title: 'Cannot Insert Image',
                    message: 'Please save the file first (Ctrl/Cmd+S) before inserting images.',
                    confirmText: 'OK',
                    onConfirm: () => setConfirmDialog(null),
                })
                return
            }

            const cfg = loadDefaultImagePathStrategyConfig()
            const { targetDir, relDir } = resolveImageTarget(filePath, null, cfg)

            const fileBaseName = (() => {
                const pathPart = filePath.split(/[/\\]/).pop() || ''
                const withoutExt = pathPart.replace(/\.[^./\\]+$/, '')
                return withoutExt || 'untitled'
            })()
            const suggestedName = `image_${fileBaseName}`

            try {
                const result = await invoke('save_clipboard_image_to_dir', {
                    targetDir,
                    suggestedName,
                }) as any

                const okPart = result && 'Ok' in result ? result.Ok : null
                if (!okPart) {
                    setStatusMessage(result?.Err?.error?.message || '粘贴图片失败：后端错误')
                    return
                }

                const fileName = okPart?.data?.file_name
                const relPath = `${relDir}/${fileName}`
                const snippet = `\n![图片](${relPath})\n`

                const { state } = view
                const { from, to } = state.selection.main
                view.dispatch(state.update({
                    changes: { from, to, insert: snippet },
                    selection: { anchor: from + snippet.length },
                    scrollIntoView: true,
                }))
            } catch (err) {
                setStatusMessage(`粘贴图片失败：${String(err)}`)
            }
        })

        return () => unlisten()
    }, [editorViewRef, filePath, setStatusMessage, setConfirmDialog])
}

import { useCallback } from 'react'
import type { SidebarContextActionPayload } from '../components/Sidebar'
import type { Result } from '../modules/files/types'
import { openInFileManager } from '../modules/platform/fileExplorerService'

export function useSidebarActions(options: {
  tabs: { id: string; path?: string | null }[]
  setActiveTab: (id: string) => void
  openFileInNewTab: (path: string) => Promise<Result<{ path: string }>>
  sidebar: {
    addStandaloneFile: (path: string) => void
    removeStandaloneFile: (path: string) => void
    removeFolderRoot: (path: string) => void
  }
  deleteFsEntry: (path: string) => Promise<Result<void>>
  setStatusMessage: (msg: string) => void
  closeTab: (id: string) => void
  setConfirmDialog: (state: any) => void
}) {
  const { tabs, setActiveTab, openFileInNewTab, sidebar, deleteFsEntry, setStatusMessage, closeTab, setConfirmDialog } = options

  const openFileFromSidebar = useCallback(
    async (path: string) => {
      const existing = tabs.find((t) => t.path === path)
      if (existing) {
        setActiveTab(existing.id)
        return { ok: true, data: { path: existing.path! } } as Result<{ path: string }>
      }
      return await openFileInNewTab(path)
    },
    [tabs, setActiveTab, openFileInNewTab],
  )

  const openRecentFileInNewTab = useCallback(
    async (path: string) => {
      const resp = await openFileInNewTab(path)
      if (!resp || !resp.ok) return resp
      sidebar.addStandaloneFile(resp.data.path)
      return resp
    },
    [openFileInNewTab, sidebar],
  )

  const closeTabsByPath = useCallback(
    (targetPath: string) => {
      const norm = targetPath
      tabs.forEach((tab) => {
        if (tab.path === norm) {
          closeTab(tab.id)
        }
      })
    },
    [tabs, closeTab],
  )

  const handleSidebarContextAction = useCallback(
    async (payload: SidebarContextActionPayload) => {
      const { path, kind, action } = payload

      if (action === 'open') {
        await openFileFromSidebar(path)
        return
      }

      if (action === 'remove') {
        if (kind === 'standalone-file') {
          sidebar.removeStandaloneFile(path)
        } else if (kind === 'folder-root') {
          sidebar.removeFolderRoot(path)
        }
        return
      }

      if (action === 'delete') {
        setConfirmDialog({
          title: '确认删除',
          message: `确认删除该文件？此操作不可撤销。\n\n${path}`,
          confirmText: '删除',
          onConfirm: async () => {
            setConfirmDialog(null)
            const resp = await deleteFsEntry(path)
            if (!resp.ok) {
              setStatusMessage(resp.error.message)
              return
            }
            sidebar.removeStandaloneFile(path)
            closeTabsByPath(path)
          },
        })
        return
      }

      if (action === 'open-in-file-manager') {
        const computeDirFromPath = (targetPath: string): string => {
          if (!targetPath) return targetPath

          const hasBackslash = targetPath.includes('\\')
          const normalized = targetPath.replace(/[\\/]/g, '/')
          const lastSlash = normalized.lastIndexOf('/')
          if (lastSlash <= 0) {
            return targetPath
          }
          let dir = normalized.slice(0, lastSlash)
          if (hasBackslash) {
            dir = dir.replace(/\//g, '\\')
          }
          return dir
        }

        const isFile = kind === 'standalone-file' || kind === 'tree-file'
        const targetPath = isFile ? computeDirFromPath(path) : path
        const result = await openInFileManager(targetPath)
        if (!result.ok && result.message) {
          setStatusMessage(result.message)
        }
        return
      }
    },
    [openFileFromSidebar, sidebar, setStatusMessage, closeTabsByPath, deleteFsEntry, setConfirmDialog],
  )

  return {
    openFileFromSidebar,
    openRecentFileInNewTab,
    handleSidebarContextAction,
  }
}

import { useCallback, useMemo, useRef, useState } from 'react'
import type { EditorTab } from '../types/tabs'

export type UseTabsOptions = {
  onRequestCloseCurrentTab?: () => void
}

const DEFAULT_UNTITLED = 'untitled.md'

function deriveTitleFromPath(path: string): string {
  if (!path) return DEFAULT_UNTITLED
  const parts = path.split(/[/\\]/)
  const last = parts[parts.length - 1]
  return last || path || DEFAULT_UNTITLED
}

function createEmptyTab(id: string): EditorTab {
  return {
    id,
    title: DEFAULT_UNTITLED,
    path: DEFAULT_UNTITLED,
    content: '',
    dirty: false,
  }
}

export function useTabs(options?: UseTabsOptions) {
  // if (import.meta.env.DEV) {
  //   console.log('[useTabs] hook 已初始化')
  // }
  const idRef = useRef(1)
  const [tabs, setTabs] = useState<EditorTab[]>(() => {
    // 初始不创建标签，返回空数组
    return []
  })
  const [activeId, setActiveId] = useState<string | null>(() => null)

  const activeTab = useMemo(
    () => tabs.find((t) => t.id === activeId) ?? null,
    [tabs, activeId],
  )

  const createTab = useCallback(
    (opts?: { title?: string; path?: string; content?: string }) => {
      const nextId = String(++idRef.current)
      const base = createEmptyTab(nextId)
      const path = opts?.path ?? base.path
      const tab: EditorTab = {
        ...base,
        ...opts,
        path,
        title: opts?.title ?? (path ? deriveTitleFromPath(path) : base.title),
        content: opts?.content ?? base.content,
      }
      setTabs((prev) => {
        if (import.meta.env.DEV) {
          console.log('[createTab] 添加标签前:', prev.map(t => ({ id: t.id, title: t.title })))
        }
        const newTabs = [...prev, tab]
        if (import.meta.env.DEV) {
          console.log('[createTab] 添加标签后:', newTabs.map(t => ({ id: t.id, title: t.title })))
        }
        return newTabs
      })
      setActiveId(nextId)
      if (import.meta.env.DEV) {
        console.log('[createTab] 设置 activeId 为:', nextId)
      }
      return tab
    },
    [],
  )

  const setActiveTab = useCallback((id: string) => {
    setActiveId(id)
  }, [])

  const closeTab = useCallback(
    (id: string) => {
      setTabs((prev) => {
        if (prev.length === 1) {
          // 最后一个标签：返回空数组，显示欢迎页
          return []
        }

        const next = prev.filter((t) => t.id !== id)
        // 更新当前激活标签
        if (id === activeId) {
          const closedIndex = prev.findIndex((t) => t.id === id)
          const fallback = next[Math.max(0, closedIndex - 1)] ?? next[0]
          setActiveId(fallback.id)
        }
        return next
      })
    },
    [activeId],
  )

  const updateTabContent = useCallback(
    (id: string, content: string, options?: { markDirty?: boolean }) => {
      const shouldMarkDirty = options?.markDirty ?? true
      setTabs((prev) =>
        prev.map((t) =>
          t.id === id
            ? {
                ...t,
                content,
                dirty: shouldMarkDirty ? true : t.dirty,
              }
            : t,
        ),
      )
    },
    [],
  )

  const updateActiveContent = useCallback(
    (content: string, options?: { markDirty?: boolean }) => {
      if (!activeId) return
      updateTabContent(activeId, content, options)
    },
    [activeId, updateTabContent],
  )

  const updateActiveMeta = useCallback(
    (path: string, dirty: boolean) => {
      if (!activeId) return
      setTabs((prev) =>
        prev.map((t) => {
          if (t.id !== activeId) return t
          const nextTitle = deriveTitleFromPath(path)
          if (import.meta.env.DEV) {
            console.log('[useTabs.updateActiveMeta]', {
              activeId,
              old: { path: t.path, title: t.title, dirty: t.dirty },
              next: { path, title: nextTitle, dirty },
            })
          }
          return {
            ...t,
            path,
            title: nextTitle,
            dirty,
          }
        }),
      )
    },
    [activeId],
  )

  const closeCurrentTab = useCallback(
    () => {
      if (import.meta.env.DEV) {
        console.log('[closeCurrentTab] 被调用')
      }
      if (!activeId) {
        if (import.meta.env.DEV) {
          console.warn('[closeCurrentTab] 没有激活标签，跳过')
        }
        return
      }

      const tab = tabs.find(t => t.id === activeId)
      if (!tab) {
        if (import.meta.env.DEV) {
          console.warn('[closeCurrentTab] 未找到当前标签，跳过', { activeId, tabs: tabs.map(t => t.id) })
        }
        return
      }

      if (import.meta.env.DEV) {
        console.log('[closeCurrentTab] 当前标签状态', { tabId: tab.id, title: tab.title, dirty: tab.dirty })
      }

      // 如果提供了 UI 层的确认回调，优先使用（与 TabBar 保持一致）
      if (options?.onRequestCloseCurrentTab) {
        if (import.meta.env.DEV) {
          console.log('[closeCurrentTab] 使用 App 层的确认对话框')
        }
        options.onRequestCloseCurrentTab()
        return
      }

      // 回退实现：如果有未保存变更，使用浏览器确认对话框
      if (tab.dirty) {
        if (import.meta.env.DEV) {
          console.log('[closeCurrentTab] 准备弹出确认对话框...')
        }
        const shouldClose = window.confirm(
          `标签 "${tab.title}" 有未保存的更改。关闭将丢弃所有更改，是否继续？`
        )
        if (import.meta.env.DEV) {
          console.log('[closeCurrentTab] 用户选择:', { shouldClose })
        }
        if (!shouldClose) {
          if (import.meta.env.DEV) {
            console.log('[closeCurrentTab] 用户取消关闭')
          }
          return
        }
      }

      if (import.meta.env.DEV) {
        console.log('[closeCurrentTab] 关闭当前标签', { tabId: tab.id, title: tab.title })
      }
      // 复用现有的 closeTab 逻辑
      closeTab(activeId)
    },
    [activeId, tabs, closeTab, options?.onRequestCloseCurrentTab],
  )

  const getUnsavedTabs = useCallback(() => {
    return tabs.filter(t => t.dirty)
  }, [tabs])

  return {
    tabs,
    activeId,
    activeTab,
    createTab,
    setActiveTab,
    closeTab,
    closeCurrentTab,
    getUnsavedTabs,
    updateTabContent,
    updateActiveContent,
    updateActiveMeta,
  }
}

import type { ChatEntryMode, ConversationState, EntryContext } from '../domain/chatSession'
import type { ChatSession, StartChatOptions } from './chatSessionService'
import { createChatSession } from './chatSessionService'

export type AiChatSessionKey = string // session key

export type SessionListener = (state: ConversationState) => void

export interface ChatSessionRecord {
  id: string
  key: AiChatSessionKey
  entryMode: ChatEntryMode
  initialContext?: EntryContext
  session: ChatSession
  state: ConversationState
  createdAt: number
  lastActiveAt: number
  disposed: boolean
}

export class AiChatSessionService {
  private sessions = new Map<AiChatSessionKey, ChatSessionRecord>()
  private listeners = new Map<AiChatSessionKey, Set<SessionListener>>()

  private genId(): string {
    return `${Date.now()}_${Math.random().toString(36).slice(2, 8)}`
  }

  getSession(key: AiChatSessionKey): ChatSessionRecord | null {
    const record = this.sessions.get(key) ?? null
    if (!record || record.disposed) return null
    return record
  }

  async getOrCreateSession(
    key: AiChatSessionKey,
    options: Omit<StartChatOptions, 'onStateChange'> & { onStateChange?: (state: ConversationState) => void } = {} as any,
  ): Promise<ChatSessionRecord> {
    const existing = this.sessions.get(key)
    if (existing && !existing.disposed) {
      return existing
    }

    const { entryMode, initialContext, onStateChange, ...rest } = options

    const startOptions: StartChatOptions = {
      entryMode,
      initialContext,
      ...(rest as any),
      onStateChange: (nextState) => {
        const current = this.sessions.get(key)
        if (!current || current.disposed) return
        current.state = nextState
        current.lastActiveAt = Date.now()
        this.notify(key, nextState)
        onStateChange?.(nextState)
      },
    }

    const session = await createChatSession(startOptions)
    const now = Date.now()
    const state = session.getState()

    const record: ChatSessionRecord = {
      id: this.genId(),
      key,
      entryMode,
      initialContext,
      session,
      state,
      createdAt: now,
      lastActiveAt: now,
      disposed: false,
    }

    this.sessions.set(key, record)
    // 初始状态也通知一次监听者
    this.notify(key, state)

    return record
  }

  subscribe(key: AiChatSessionKey, listener: SessionListener): () => void {
    let set = this.listeners.get(key)
    if (!set) {
      set = new Set()
      this.listeners.set(key, set)
    }
    set.add(listener)

    const record = this.sessions.get(key)
    if (record && !record.disposed) {
      listener(record.state)
    }

    return () => {
      const currentSet = this.listeners.get(key)
      if (!currentSet) return
      currentSet.delete(listener)
      if (currentSet.size === 0) {
        this.listeners.delete(key)
      }
    }
  }

  updateSessionState(
    key: AiChatSessionKey,
    updater: (prev: ConversationState) => ConversationState,
  ): void {
    const record = this.sessions.get(key)
    if (!record || record.disposed) return
    const next = updater(record.state)
    record.state = next
    record.lastActiveAt = Date.now()
    this.notify(key, next)
  }

  disposeSession(key: AiChatSessionKey): void {
    const record = this.sessions.get(key)
    if (!record || record.disposed) return

    record.disposed = true
    try {
      record.session.dispose()
    } catch (e) {
      console.error('[AiChatSessionService] disposeSession error', e)
    }

    this.sessions.delete(key)
    this.listeners.delete(key)
  }

  disposeAll(): void {
    for (const key of this.sessions.keys()) {
      this.disposeSession(key)
    }
  }

  private notify(key: AiChatSessionKey, state: ConversationState): void {
    const set = this.listeners.get(key)
    if (!set || set.size === 0) return
    for (const listener of set) {
      try {
        listener(state)
      } catch (e) {
        console.error('[AiChatSessionService] listener error', e)
      }
    }
  }
}

import type { UiProvider } from '../settings'
import { loadAiSettingsState } from '../settings'
import type {
  IStreamingChatClient,
  ChatMessage,
  ProviderType,
