import type { FC, MouseEventHandler, MouseEvent as ReactMouseEvent } from 'react'
import { useCallback, useEffect, useMemo, useRef, useState } from 'react'
import { invoke } from '@tauri-apps/api/core'
import type { DocConversationMessage, DocConversationRecord } from '../domain/docConversations'
import { docConversationService } from '../application/docConversationService'

export type DocConversationHistoryDialogProps = {
  open: boolean
  docPath: string
  onClose: () => void
}

type ConversationGroup = {
  id: string
  userMessages: DocConversationMessage[]
  assistantMessages: DocConversationMessage[]
  systemMessages: DocConversationMessage[]
  startedAt: number
}

function buildConversationGroups(messages: DocConversationMessage[]): ConversationGroup[] {
  if (!messages.length) return []

  const sorted = [...messages].sort((a, b) => a.timestamp - b.timestamp)
  const groups: ConversationGroup[] = []
  let current: ConversationGroup | null = null

  for (const m of sorted) {
    if (!current) {
      current = {
        id: m.id,
        userMessages: [],
        assistantMessages: [],
        systemMessages: [],
        startedAt: m.timestamp,
      }
      groups.push(current)
    }

    if (m.role === 'system') {
      current.systemMessages.push(m)
      continue
    }

    if (m.role === 'user') {
      // 简单策略：如果当前组已经有 user 或 assistant，则开启新组；否则归入当前组
      if (current.userMessages.length > 0 || current.assistantMessages.length > 0) {
        current = {
          id: m.id,
          userMessages: [m],
          assistantMessages: [],
          systemMessages: [],
          startedAt: m.timestamp,
        }
        groups.push(current)
      } else {
        current.userMessages.push(m)
      }
      continue
    }

    if (m.role === 'assistant') {
      current.assistantMessages.push(m)
      continue
    }
  }

  return groups
}

function buildMarkdownFromDocRecord(record: DocConversationRecord, groups: ConversationGroup[]): string {
  const lines: string[] = []

  lines.push('# AI 会话历史（当前目录会话）')
  lines.push('')
  lines.push(`- 导出时间：${new Date().toLocaleString()}`)
  lines.push(`- 总消息数：${record.messages.length}`)
  lines.push(`- 总对话轮次：${groups.length}`)
  lines.push('')
  lines.push('---')
  lines.push('')

  groups.forEach((g, index) => {
    lines.push(`## 对话 ${index + 1}`)
    lines.push('')

    if (g.systemMessages.length) {
      g.systemMessages.forEach((m) => {
        lines.push('**System**')
        lines.push('')
        lines.push(`> ${m.content}`)
        lines.push('')
      })
    }

    if (g.userMessages.length) {
      const first = g.userMessages[0]
      lines.push(`- 时间：${new Date(first.timestamp).toLocaleString()}`)
      lines.push('')
      lines.push('**User**')
      lines.push('')
      g.userMessages.forEach((m) => {
        lines.push(`> ${m.content}`)
        lines.push('')
      })
    }

    if (g.assistantMessages.length) {
      const first = g.assistantMessages[0]
      const meta = first.meta || {}
      const provider = meta.providerType ?? 'unknown'
      const model = meta.modelName ?? ''
      const label = model ? `${provider} / ${model}` : provider
      lines.push(`**Assistant: （${label}）**`)
      lines.push('')
      g.assistantMessages.forEach((m) => {
        lines.push(`> ${m.content}`)
        lines.push('')
      })
    }

    lines.push('---')
    lines.push('')
  })

  return lines.join('\n')
}

export const DocConversationHistoryDialog: FC<DocConversationHistoryDialogProps> = ({ open, docPath, onClose }) => {
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<Error | null>(null)
  const [record, setRecord] = useState<DocConversationRecord | null>(null)
  const [groups, setGroups] = useState<ConversationGroup[]>([])
  const [pageIndex, setPageIndex] = useState(0)
  const [pageSize, setPageSize] = useState(10)

  const [dragOffset, setDragOffset] = useState({ x: 0, y: 0 })
  const [dragging, setDragging] = useState(false)
  const dragStateRef = useRef<{ startX: number; startY: number; originX: number; originY: number } | null>(null)

  useEffect(() => {
    if (!open) return

    let cancelled = false
    setLoading(true)
    setError(null)

    ;(async () => {
      try {
        const rec = await docConversationService.getByDocPath(docPath)
        if (cancelled) return
        setRecord(rec)

        if (!rec || !rec.messages.length) {
          setGroups([])
          setPageIndex(0)
          return
        }

        const built = buildConversationGroups(rec.messages)
        setGroups(built)

        // 默认跳到最后一页（最新对话）
        const totalPages = Math.max(1, Math.ceil(built.length / pageSize))
        setPageIndex(totalPages - 1)
      } catch (e) {
        if (cancelled) return
        setError(e as Error)
      } finally {
        if (!cancelled) setLoading(false)
      }
    })()

    return () => {
      cancelled = true
    }
  }, [open, docPath, pageSize])

  const hasData = !!record && record.messages.length > 0 && groups.length > 0

  const { pageGroups, totalPages, displayPageIndex } = useMemo(() => {
    if (!groups.length) {
      return {
        pageGroups: [] as ConversationGroup[],
        totalPages: 1,
        displayPageIndex: 0,
      }
    }

    const total = Math.max(1, Math.ceil(groups.length / pageSize))
    const safeIndex = Math.min(Math.max(pageIndex, 0), total - 1)
    const start = safeIndex * pageSize
    const end = start + pageSize

    return {
      pageGroups: groups.slice(start, end),
      totalPages: total,
      displayPageIndex: safeIndex,
    }
  }, [groups, pageIndex, pageSize])

  const handlePrevPage = useCallback(() => {
    setPageIndex((prev) => Math.max(0, prev - 1))
  }, [])

  const handleNextPage = useCallback(() => {
    setPageIndex((prev) => {
      const total = Math.max(1, Math.ceil(groups.length / pageSize))
      return Math.min(total - 1, prev + 1)
    })
  }, [groups.length, pageSize])

  const handlePageSizeChange = useCallback((e: React.ChangeEvent<HTMLSelectElement>) => {
    const next = Number(e.target.value)
    if (!Number.isNaN(next) && next > 0) {
      setPageSize(next)
      // 重置到最后一页，方便查看最新对话
      const total = Math.max(1, Math.ceil(groups.length / next))
      setPageIndex(total - 1)
    }
  }, [groups.length])

  const handleDragStart: MouseEventHandler<HTMLDivElement> = (e: ReactMouseEvent<HTMLDivElement>) => {
    if (e.button !== 0) return
    const target = e.target as HTMLElement | null
    if (target) {
      const interactive = target.closest('select, button, input, textarea')
      if (interactive) return
    }
    const { clientX, clientY } = e
    dragStateRef.current = {
      startX: clientX,
      startY: clientY,
      originX: dragOffset.x,
      originY: dragOffset.y,
    }
    setDragging(true)
    e.preventDefault()
  }

  useEffect(() => {
    if (!dragging) return
    const handleMove = (e: MouseEvent) => {
      const state = dragStateRef.current
      if (!state) return
      const dx = e.clientX - state.startX
      const dy = e.clientY - state.startY
      setDragOffset({ x: state.originX + dx, y: state.originY + dy })
    }
    const handleUp = () => {
      setDragging(false)
      dragStateRef.current = null
    }
    window.addEventListener('mousemove', handleMove)
    window.addEventListener('mouseup', handleUp)
    return () => {
      window.removeEventListener('mousemove', handleMove)
      window.removeEventListener('mouseup', handleUp)
    }
  }, [dragging])

  if (!open) return null

  const handleExportMarkdown = useCallback(async () => {
    if (!record) return
    try {
      const content = buildMarkdownFromDocRecord(record, groups)
      const now = new Date()
      const yyyy = now.getFullYear()
      const mm = String(now.getMonth() + 1).padStart(2, '0')
      const dd = String(now.getDate()).padStart(2, '0')
      const hh = String(now.getHours()).padStart(2, '0')
      const mi = String(now.getMinutes()).padStart(2, '0')
      const ts = `${yyyy}${mm}${dd}-${hh}${mi}`
      const baseName = docPath.split(/[/\\]/).pop()?.replace(/\.[^./\\]+$/, '') || 'document'
      const defaultFileName = `AI History - ${baseName} - ${ts}.md`

      await invoke('save_text_with_dialog', {
        defaultFileName,
        content,
      })
    } catch (e) {
      // 仅在控制台记录错误，不阻塞 UI
      console.error('[DocConversationHistoryDialog] export markdown failed', e)
    }
  }, [record, groups, docPath])

  const summaryLine = (() => {
    if (!record || !record.messages.length) return '当前目录暂无 AI 会话历史'
    const lastTs = new Date(record.lastActiveAt).toLocaleString()
    return `最近活跃时间：${lastTs} · 总消息数：${record.messages.length} · 总对话轮次：${groups.length}`
  })()

  return (
    <div className="modal-backdrop modal-backdrop-plain" onClick={onClose}>
      <div
        className="modal modal-ai-chat modal-ai-history"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="modal-title ai-chat-title">
          <button
            type="button"
            className="ai-chat-close-button"
            aria-label="关闭会话历史"
            onClick={onClose}
          >
            <span className="ai-chat-close-icon" aria-hidden="true" />
          </button>
          <div className="modal-title-text">AI Session History</div>
          <div className="ai-history-actions">
            <button
              type="button"
              className="ai-history-export-button"
              onClick={handleExportMarkdown}
            >
              导出 Markdown
            </button>
          </div>
        </div>

        <div className="ai-history-summary">
          {loading && <div className="ai-history-status">正在加载文档会话历史…</div>}
          {!loading && error && (
            <div className="ai-history-status ai-history-status-error">加载失败：{error.message}</div>
          )}
          {!loading && !error && (
            <div className="ai-history-status">{summaryLine}</div>
          )}
        </div>

        <div className="ai-history-body">
          {!loading && !error && !hasData && (
            <div className="ai-history-empty">
              当前目录暂无 AI 会话历史。
              <br />
              你可以通过 AI Chat 或 Ask File / Ask Selection 发起对话，历史会自动记录在这里。
            </div>
          )}

          {!loading && !error && hasData && (
            <div className="ai-history-list">
              {pageGroups.map((group, idx) => {
                const groupIndex = displayPageIndex * pageSize + idx + 1
                return (
                  <div className="ai-history-group" key={group.id}>
                    <div className="ai-history-group-header">
                      <span className="ai-history-group-title">对话 {groupIndex}</span>
                    </div>

                    {group.systemMessages.map((m) => (
                      <div key={m.id} className="ai-history-message ai-history-message-system">
                        <div className="ai-history-message-meta">
                          {(() => {
                            const level = m.meta?.summaryLevel ?? 0
                            return level >= 1 ? `摘要 (Level ${level})` : 'System'
                          })()}
                        </div>
                        <div className="ai-history-message-content">{m.content}</div>
                      </div>
                    ))}

                    {group.userMessages.length > 0 && (
                      <div className="ai-history-message ai-history-message-user">
                        <div className="ai-history-message-meta">
                          <span className="ai-history-role">User</span>
                          <span className="ai-history-time">
                            {new Date(group.userMessages[0].timestamp).toLocaleString()}
                          </span>
                        </div>
                        <div className="ai-history-message-content">
                          {group.userMessages.map((m) => (
                            <p key={m.id}>{m.content}</p>
                          ))}
                        </div>
                      </div>
                    )}

                    {group.assistantMessages.length > 0 && (
                      <div className="ai-history-message ai-history-message-assistant">
                        <div className="ai-history-message-meta">
                          <span className="ai-history-role">Assistant</span>
                          <span className="ai-history-model">
                            {(() => {
                              const meta = group.assistantMessages[0].meta
                              const provider = meta?.providerType ?? 'unknown'
                              const model = meta?.modelName ?? ''
                              return model ? `${provider} / ${model}` : provider
                            })()}
                          </span>
                        </div>
                        <div className="ai-history-message-content">
                          {group.assistantMessages.map((m) => (
                            <p key={m.id}>{m.content}</p>
                          ))}
                        </div>
                      </div>
                    )}

                    <div className="ai-history-group-divider" />
                  </div>
                )
              })}
            </div>
          )}
        </div>

        <div className="ai-history-footer">
          <div className="ai-history-pagination">
            <button
              type="button"
              className="ai-history-page-button"
              onClick={handlePrevPage}
              disabled={displayPageIndex <= 0}
            >
              上一页
            </button>
            <span className="ai-history-page-info">
              第 {displayPageIndex + 1} / {totalPages} 页
            </span>
            <button
              type="button"
              className="ai-history-page-button"
              onClick={handleNextPage}
              disabled={displayPageIndex >= totalPages - 1}
            >
              下一页
            </button>
          </div>

          <div className="ai-history-page-size">
            每页
            <select value={pageSize} onChange={handlePageSizeChange}>
              <option value={5}>5 组</option>
              <option value={10}>10 组</option>
              <option value={20}>20 组</option>
            </select>
            对话
          </div>
        </div>

        <div className="ai-chat-drag-handle ai-chat-drag-bottom" onMouseDown={handleDragStart} />
        <div className="ai-chat-drag-handle ai-chat-drag-left" onMouseDown={handleDragStart} />
        <div className="ai-chat-drag-handle ai-chat-drag-right" onMouseDown={handleDragStart} />
      </div>
    </div>
  )
}

import { useCallback, useEffect, useState } from 'react'
import type { ChatEntryMode, ConversationState, EntryContext, ChatMessageView } from '../../domain/chatSession'
import type { SystemPromptInfo } from '../../application/systemPromptService'
import type { ProviderType, VisionTask, UploadedFileRef } from '../../domain/types'
import type { ChatSession, StartChatOptions } from '../../application/chatSessionService'
import { createChatSession } from '../../application/chatSessionService'
import { aiChatSessionManager } from '../../application/localStorageAiChatSessionManager'

export type UseAiChatOptions = {
  entryMode: ChatEntryMode
  initialContext?: EntryContext
  open: boolean
  /**
   * Tab ID：用于在本地持久化与恢复会话。
   */
  tabId: string
  /**
   * 可选：当前对话关联的文档路径，用于文档会话历史持久化。
   */
  docPath?: string
}

export type UseAiChatResult = {
  loading: boolean
  state: ConversationState | null
  systemPromptInfo: SystemPromptInfo | null
  providerType: ProviderType | null
  error: Error | null
  send: (content: string, options?: { hideUserInView?: boolean }) => Promise<void>
  sendMessage: (
    input: string,
    options?: {
      contextPrefix?: string | null
      contextPrefixUsed?: boolean
      onContextUsed?: () => void
      attachedImageDataUrl?: string | null
      onClearAttachedImage?: () => void
    },
  ) => Promise<void>
  sendVisionTask: (task: VisionTask, options?: { hideUserInView?: boolean }) => Promise<void>
  stop: () => void
  stopAndTruncate: (messageId: string, length: number) => void
  changeRole: (roleId: string) => Promise<void>
  changeModel: (modelId: string) => Promise<void>
  resetError: () => void
  availableModels: { id: string; providerName: string }[]
  activeModelId: string | null
  pendingAttachments: UploadedFileRef[]
  uploadFiles: (files: File[]) => Promise<void>
  removeAttachment: (id: string) => void
  isUploading: boolean
  /**
   * 提供给 /remember 等功能使用的“近期会话消息视图”。
   * 只包含未隐藏的 user/assistant 消息，并按时间顺序返回最后 limit 条。
   */
  getRecentMessagesForDigest: (limit: number) => ChatMessageView[]
}

export function useAiChat(options: UseAiChatOptions): UseAiChatResult {
  const { entryMode, initialContext, open, tabId, docPath } = options
  const [session, setSession] = useState<ChatSession | null>(null)
  const [loading, setLoading] = useState(false)
  const [state, setState] = useState<ConversationState | null>(null)
  const [systemPromptInfo, setSystemPromptInfo] = useState<SystemPromptInfo | null>(null)
  const [providerType, setProviderType] = useState<ProviderType | null>(null)
  const [error, setError] = useState<Error | null>(null)
  const [activeModelId, setActiveModelId] = useState<string | null>(null)
  const [rawModels, setRawModels] = useState<{ id: string; providerName: string }[]>([])
  const [pendingAttachments, setPendingAttachments] = useState<UploadedFileRef[]>([])
  const [uploadingCount, setUploadingCount] = useState(0)

  useEffect(() => {
    if (!open) {
      return
    }

    let cancelled = false
    setLoading(true)
    setError(null)

    const startSession = async () => {
      try {
        const saved = aiChatSessionManager.getOrCreateSession(tabId)
        let createdSession: ChatSession | null = null

        if (saved) {
          // 1. 先用已保存的状态填充 UI
          setState(saved.state)
          setSystemPromptInfo(saved.systemPromptInfo)
          setProviderType(saved.providerType)

          const startOptions: StartChatOptions = {
            entryMode: saved.entryMode,
            initialContext: saved.initialContext,
            initialState: saved.state,
            ...(docPath ? { docPath } : {}),
            onStateChange: (nextState) => {
              if (cancelled) return
              setState(nextState)
              if (createdSession) {
                aiChatSessionManager.saveSession(tabId, {
                  state: nextState,
                  systemPromptInfo: createdSession.getSystemPromptInfo(),
                  providerType: createdSession.getProviderType(),
                  entryMode: saved.entryMode,
                  initialContext: saved.initialContext,
                })
              }
            },
          }

          const created = await createChatSession(startOptions)
          createdSession = created

          if (cancelled) {
            created.dispose()
            return
          }

          setSession(created)
          setState(created.getState())
          setSystemPromptInfo(created.getSystemPromptInfo())
          setProviderType(created.getProviderType())
          setActiveModelId(created.getActiveModelId())
        } else {
          const startOptions: StartChatOptions = {
            entryMode,
            initialContext,
            ...(docPath ? { docPath } : {}),
            onStateChange: (nextState) => {
              if (cancelled) return
              setState(nextState)
              if (createdSession) {
                aiChatSessionManager.saveSession(tabId, {
                  state: nextState,
                  systemPromptInfo: createdSession.getSystemPromptInfo(),
                  providerType: createdSession.getProviderType(),
                  entryMode,
                  initialContext,
                })
              }
            },
          }

          const created = await createChatSession(startOptions)
          createdSession = created

          if (cancelled) {
            created.dispose()
            return
          }

          setSession(created)
          const initialState = created.getState()
          setState(initialState)
          const info = created.getSystemPromptInfo()
          const type = created.getProviderType()
          setSystemPromptInfo(info)
          setProviderType(type)
          setActiveModelId(created.getActiveModelId())

          // 首次创建立即持久化一次
          aiChatSessionManager.saveSession(tabId, {
            state: initialState,
            systemPromptInfo: info,
            providerType: type,
            entryMode,
            initialContext,
          })
        }
      } catch (e) {
        if (cancelled) return
        setError(e as Error)
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    void startSession()

    return () => {
      cancelled = true
      setSession((prev) => {
        if (prev) {
          prev.dispose()
        }
        return null
      })
    }
  }, [open, entryMode, initialContext, tabId])

  // Load available models
  useEffect(() => {
    if (!open) return
    const loadModels = async () => {
      const { loadAiSettingsState } = await import('../../config/aiSettingsRepo')
      const settings = await loadAiSettingsState()
      const models = settings.providers.flatMap((p) =>
        p.models.map((m) => ({
          id: m.id,
          providerName: p.name,
        })),
      )
      setRawModels(models)
    }
    void loadModels()
  }, [open])

  const isGenerating = !!state?.viewMessages.some((m) => m.streaming) || loading

  const send = useCallback(
    async (content: string, options?: { hideUserInView?: boolean }) => {
      if (!session) return
      setError(null)
      setLoading(true)
      try {
        await session.sendUserMessage(content, {
          hideInView: options?.hideUserInView,
          attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined
        })
        setPendingAttachments([]) // Clear after sending
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session, pendingAttachments],
  )

  const uploadFiles = useCallback(async (files: File[]) => {
    if (!session) {
      console.warn('[useAiChat] uploadFiles ignored: no session')
      return
    }
    console.warn('[useAiChat] uploadFiles starting for:', files.map(f => f.name))
    setUploadingCount(prev => prev + files.length)
    try {
      const results = await Promise.all(
        files.map(file => session.uploadAttachment(file))
      )
      console.warn('[useAiChat] uploadFiles success:', results)
      setPendingAttachments(prev => [...prev, ...results])
    } catch (e) {
      console.warn('[useAiChat] uploadFiles error:', e)
      setError(e as Error)
    } finally {
      setUploadingCount(prev => Math.max(0, prev - files.length))
    }
  }, [session])

  const removeAttachment = useCallback((id: string) => {
    console.warn('[useAiChat] removeAttachment:', id)
    setPendingAttachments(prev => prev.filter(a => a.id !== id))
  }, [])

  const sendVisionTask = useCallback(
    async (task: VisionTask, options?: { hideUserInView?: boolean }) => {
      if (!session) return
      setError(null)
      setLoading(true)
      try {
        await session.sendVisionTask(task, { hideInView: options?.hideUserInView })
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session],
  )

  const changeRole = useCallback(
    async (roleId: string) => {
      if (!session) return
      setError(null)
      await session.setActiveRole(roleId)
      setSystemPromptInfo(session.getSystemPromptInfo())
    },
    [session],
  )

  const changeModel = useCallback(
    async (modelId: string) => {
      if (!session) return
      setError(null)
      try {
        console.warn('[useAiChat] changing model to:', modelId)
        await session.setActiveModel?.(modelId)

        // 关键点：切换后立即重新获取 providerType 并更新 UI 状态
        const nextProviderType = session.getProviderType()
        console.warn('[useAiChat] model change complete. nextProviderType:', nextProviderType)

        setActiveModelId(session.getActiveModelId?.() ?? modelId)
        setProviderType(nextProviderType)
      } catch (e) {
        console.error('[useAiChat] changeModel error:', e)
        setError(e as Error)
      }
    },
    [session],
  )

  const DEFAULT_VISION_PROMPT = '解析图片并根据上下文回复图片中内容的含义'

  const sendMessage = useCallback(
    async (
      input: string,
      options?: {
        contextPrefix?: string | null;
        contextPrefixUsed?: boolean;
        onContextUsed?: () => void;
        attachedImageDataUrl?: string | null;
        onClearAttachedImage?: () => void;
      }
    ) => {
      if (!session) return
      setError(null)

      const raw = input
      const trimmed = raw.trim()
      const isDify = providerType === 'dify'
      const hasAttachments = isDify ? pendingAttachments.length > 0 : !!options?.attachedImageDataUrl

      // 没有文字、没有上下文、也没有图片时不发送
      if (!trimmed && !options?.contextPrefix && !hasAttachments) return

      const basePrompt = trimmed || (hasAttachments ? DEFAULT_VISION_PROMPT : '')

      let finalContent = basePrompt
      let hideUserInView = false

      if (options?.contextPrefix && !options?.contextPrefixUsed) {
        finalContent = basePrompt ? `${options.contextPrefix}\n\n${basePrompt}` : options.contextPrefix
        options.onContextUsed?.()
        // 有真实输入时在 UI 保留这条“提问”消息；
        // 仅在“纯上下文（只发选区/文件，不输入问题）”时隐藏 user 气泡。
        hideUserInView = !basePrompt
      }

      setLoading(true)
      try {
        if (options?.attachedImageDataUrl && !isDify) {
          const visionTask: VisionTask = {
            prompt: finalContent,
            images: [{ kind: 'data_url', dataUrl: options.attachedImageDataUrl }],
          }
          await session.sendVisionTask(visionTask, { hideInView: hideUserInView })
          options.onClearAttachedImage?.()
        } else {
          await session.sendUserMessage(finalContent, {
            hideInView: hideUserInView,
            attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined,
            // 只在 UI 中展示用户真实输入的问题部分，
            // selection/file 上下文只进入 engineHistory，不出现在气泡里。
            viewContent: basePrompt,
          })
          setPendingAttachments([])
        }
      } catch (e) {
        const error = e as Error
        if (error.name !== 'AbortError') {
          console.error('[useAiChat] sendMessage error:', e)
          setError(error)
        }
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session, providerType, pendingAttachments],
  )

  const stop = useCallback(() => {
    console.log('[useAiChat] stop called', { hasSession: !!session })
    if (session) {
      session.stopRunningStream()
    }
  }, [session])

  const stopAndTruncate = useCallback(
    (messageId: string, length: number) => {
      console.log('[useAiChat] stopAndTruncate called', { messageId, length, hasSession: !!session })
      if (session) {
        session.stopAndTruncate(messageId, length)
      }
    },
    [session],
  )

  const resetError = useCallback(() => {
    setError(null)
  }, [])

  const getRecentMessagesForDigest: UseAiChatResult['getRecentMessagesForDigest'] = useCallback(
    (limit: number) => {
      const messages = state?.viewMessages ?? []
      const visible = messages.filter((m) => !m.hidden)
      if (limit <= 0 || visible.length <= limit) return visible
      return visible.slice(-limit)
    },
    [state],
  )

  return {
    loading: isGenerating, // Rename derived state to loading for UI compatibility
    state,
    systemPromptInfo,
    providerType,
    error,
    send,
    sendMessage,
    sendVisionTask,
    stop,
    stopAndTruncate,
    changeRole,
    changeModel,
    resetError,
    availableModels: rawModels,
    activeModelId,
    pendingAttachments,
    uploadFiles,
    removeAttachment,
    isUploading: uploadingCount > 0,
    getRecentMessagesForDigest,
  }
}

import { useCallback, useEffect, useState } from 'react'
import type {
  ChatEntryMode,
  ConversationState,
  EntryContext,
  ChatMessageView,
  EngineMessage,
  ChatRole,
} from '../../domain/chatSession'
import type { SystemPromptInfo } from '../../application/systemPromptService'
import type { ProviderType, VisionMode, VisionTask, UploadedFileRef } from '../../domain/types'
import type { UseAiChatResult } from './useAiChat'
import type { AiChatSessionKey } from '../../application/aiChatSessionService'
import type { ChatSession, StartChatOptions } from '../../application/chatSessionService'
import { createChatSession } from '../../application/chatSessionService'
import { docConversationService, subscribeDocConversationEvents, type DocConversationEvent } from '../../application/docConversationService'
import type { DocConversationRecord } from '../../domain/docConversations'

export type UseAiChatSessionOptions = {
  sessionKey: AiChatSessionKey
  entryMode: ChatEntryMode
  initialContext?: EntryContext
  open: boolean
  /** 当前会话关联的文档路径（目录级 key），用于文档级会话历史持久化与恢复 */
  docPath?: string
  /** 旧版文档级会话使用的原始 docPath（文件路径），用于懒迁移 */
  legacyDocPath?: string
}

function buildStateFromDocRecord(record: DocConversationRecord, entryMode: ChatEntryMode): ConversationState {
  const engineHistory: EngineMessage[] = record.messages.map((m): EngineMessage => ({
    role: m.role,
    content: m.content,
  }))

  const viewMessages: ChatMessageView[] = record.messages
    .filter((m) => m.role === 'user' || m.role === 'assistant')
    .map((m): ChatMessageView => ({
      id: m.id,
      role: m.role as ChatRole,
      content: m.content,
    }))

  return {
    engineHistory,
    viewMessages,
    entryMode,
  }
}

export function useAiChatSession(options: UseAiChatSessionOptions): UseAiChatResult {
  const { entryMode, initialContext, open, docPath, legacyDocPath } = options

  const [session, setSession] = useState<ChatSession | null>(null)
  const [loading, setLoading] = useState(false)
  const [state, setState] = useState<ConversationState | null>(null)
  const [systemPromptInfo, setSystemPromptInfo] = useState<SystemPromptInfo | null>(null)
  const [providerType, setProviderType] = useState<ProviderType | null>(null)
  const [error, setError] = useState<Error | null>(null)
  const [activeModelId, setActiveModelId] = useState<string | null>(null)
  const [rawModels, setRawModels] = useState<{ id: string; providerName: string; visionMode?: VisionMode }[]>([])
  const [pendingAttachments, setPendingAttachments] = useState<UploadedFileRef[]>([])
  const [uploadingCount, setUploadingCount] = useState(0)
  const [reloadToken, setReloadToken] = useState(0)

  useEffect(() => {
    if (!docPath) return

    const unsubscribe = subscribeDocConversationEvents((event: DocConversationEvent) => {
      if (event.docPath !== docPath) return

      if (event.type === 'cleared') {
        // 清空当前 UI 并触发一次会话重建
        setState(null)
        setPendingAttachments([])
        setReloadToken((prev) => prev + 1)
        return
      }

      if (event.type === 'compressed') {
        // 文档会话已被压缩：重建当前会话，以便 UI 与最新摘要后的历史保持一致
        setState(null)
        setReloadToken((prev) => prev + 1)
      }
    })

    return () => {
      unsubscribe()
    }
  }, [docPath])

  useEffect(() => {
    if (!open) return

    let cancelled = false
    setLoading(true)
    setError(null)

    const startSession = async () => {
      try {
        let initialState: ConversationState | undefined
        let initialDifyConversationId: string | undefined
        let initialDifyMapping: Record<string, string> | undefined

        if (docPath) {
          let saved: DocConversationRecord | null = await docConversationService.getByDocPath(docPath)

          // 懒迁移：如果目录级 docPath 下没有记录，且提供了旧版文件级 docPath，则尝试回退加载
          if (!saved && legacyDocPath && legacyDocPath !== docPath) {
            try {
              saved = await docConversationService.getByDocPath(legacyDocPath)
            } catch (e) {
              console.warn('[useAiChatSession] failed to load legacy doc conversation', e)
            }
          }

          if (saved) {
            initialState = buildStateFromDocRecord(saved, entryMode)
            initialDifyConversationId = saved.difyConversationId
            initialDifyMapping = saved.difyProviderConversations
          }
        }

        const startOptions: StartChatOptions = {
          entryMode,
          initialContext,
          ...(initialState ? { initialState } : {}),
          ...(docPath ? { docPath } : {}),
          ...(initialDifyConversationId ? { initialDifyConversationId } : {}),
          ...(initialDifyMapping ? { initialDifyProviderConversations: initialDifyMapping } : {}),
          onStateChange: (nextState) => {
            if (cancelled) return
            setState(nextState)
          },
        }

        const created = await createChatSession(startOptions)
        if (cancelled) {
          created.dispose()
          return
        }

        setSession(created)
        setState(created.getState())
        setSystemPromptInfo(created.getSystemPromptInfo())
        setProviderType(created.getProviderType())
        setActiveModelId(created.getActiveModelId())
      } catch (e) {
        if (cancelled) return
        setError(e as Error)
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    void startSession()

    return () => {
      cancelled = true
      setSession((prev) => {
        if (prev) {
          prev.dispose()
        }
        return null
      })
    }
  }, [open, entryMode, initialContext, docPath, reloadToken])

  // Load available models
  useEffect(() => {
    if (!open) return
    const loadModels = async () => {
      const { loadAiSettingsState } = await import('../../config/aiSettingsRepo')
      const settings = await loadAiSettingsState()
      const models = settings.providers.flatMap((p) =>
        p.models.map((m) => {
          const effectiveVisionMode: VisionMode | undefined = m.visionMode ?? p.visionMode
          return {
            id: m.id,
            providerName: p.name,
            visionMode: effectiveVisionMode,
          }
        }),
      )
      setRawModels(models)
    }
    void loadModels()
  }, [open])

  const isGenerating = !!state?.viewMessages.some((m) => m.streaming) || loading

  const send = useCallback<UseAiChatResult['send']>(
    async (content, options) => {
      if (!session) return
      setError(null)
      setLoading(true)
      try {
        await session.sendUserMessage(content, {
          hideInView: options?.hideUserInView,
          attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined,
        })
        setPendingAttachments([])
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session, pendingAttachments],
  )

  const uploadFiles = useCallback<UseAiChatResult['uploadFiles']>(
    async (files) => {
      if (!session) {
        console.warn('[useAiChatSession] uploadFiles ignored: no session')
        return
      }
      console.warn('[useAiChatSession] uploadFiles starting for:', files.map((f) => f.name))
      setUploadingCount((prev) => prev + files.length)
      try {
        const results = await Promise.all(files.map((file) => session.uploadAttachment(file)))
        console.warn('[useAiChatSession] uploadFiles success:', results)
        setPendingAttachments((prev) => [...prev, ...results])
      } catch (e) {
        console.warn('[useAiChatSession] uploadFiles error:', e)
        setError(e as Error)
      } finally {
        setUploadingCount((prev) => Math.max(0, prev - files.length))
      }
    },
    [session],
  )

  const removeAttachment = useCallback<UseAiChatResult['removeAttachment']>((id) => {
    console.warn('[useAiChatSession] removeAttachment:', id)
    setPendingAttachments((prev) => prev.filter((a) => a.id !== id))
  }, [])

  const sendVisionTask = useCallback<UseAiChatResult['sendVisionTask']>(
    async (task, options) => {
      if (!session) return
      setError(null)
      setLoading(true)
      try {
        await session.sendVisionTask(task, { hideInView: options?.hideUserInView })
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session],
  )

  const changeRole = useCallback<UseAiChatResult['changeRole']>(
    async (roleId) => {
      if (!session) return
      setError(null)
      await session.setActiveRole(roleId)
      setSystemPromptInfo(session.getSystemPromptInfo())
    },
    [session],
  )

  const changeModel = useCallback<UseAiChatResult['changeModel']>(
    async (modelId) => {
      if (!session) return
      setError(null)
      try {
        console.warn('[useAiChatSession] changing model to:', modelId)
        await session.setActiveModel?.(modelId)

        const nextProviderType = session.getProviderType()
        console.warn('[useAiChatSession] model change complete. nextProviderType:', nextProviderType)

        setActiveModelId(session.getActiveModelId?.() ?? modelId)
        setProviderType(nextProviderType)
      } catch (e) {
        console.error('[useAiChatSession] changeModel error:', e)
        setError(e as Error)
      }
    },
    [session],
  )

  const DEFAULT_VISION_PROMPT = '解析图片并根据上下文回复图片中内容的含义'

  const sendMessage = useCallback<UseAiChatResult['sendMessage']>(
    async (input, options) => {
      if (!session) return
      setError(null)

      const raw = input
      const trimmed = raw.trim()
      const isDify = providerType === 'dify'
      const hasAttachments = isDify ? pendingAttachments.length > 0 : !!options?.attachedImageDataUrl

      if (!trimmed && !options?.contextPrefix && !hasAttachments) return

      const basePrompt = trimmed || (hasAttachments ? DEFAULT_VISION_PROMPT : '')

      let finalContent = basePrompt
      let hideUserInView = false

      if (options?.contextPrefix && !options?.contextPrefixUsed) {
        finalContent = basePrompt ? `${options.contextPrefix}\n\n${basePrompt}` : options.contextPrefix
        options.onContextUsed?.()
        // 有真实输入时在 UI 保留这条“提问”消息；
        // 仅在“纯上下文（只发选区/文件，不输入问题）”时隐藏 user 气泡。
        hideUserInView = !basePrompt
      }

      setLoading(true)
      try {
        if (options?.attachedImageDataUrl && !isDify) {
          const visionTask: VisionTask = {
            prompt: finalContent,
            images: [{ kind: 'data_url', dataUrl: options.attachedImageDataUrl }],
          }
          await session.sendVisionTask(visionTask, { hideInView: hideUserInView })
          options.onClearAttachedImage?.()
        } else {
          await session.sendUserMessage(finalContent, {
            hideInView: hideUserInView,
            attachments: pendingAttachments.length > 0 ? pendingAttachments : undefined,
            // 只在 UI 中展示用户真实输入的问题部分，
            // selection/file 上下文只进入 engineHistory，不出现在气泡里。
            viewContent: basePrompt,
          })
          setPendingAttachments([])
        }
      } catch (e) {
        const err = e as Error
        if (err.name !== 'AbortError') {
          console.error('[useAiChatSession] sendMessage error:', e)
          setError(err)
        }
      } finally {
        setLoading(false)
        setState(session.getState())
        setSystemPromptInfo(session.getSystemPromptInfo())
      }
    },
    [session, providerType, pendingAttachments],
  )

  const stop = useCallback<UseAiChatResult['stop']>(() => {
    console.log('[useAiChatSession] stop called', { hasSession: !!session })
    if (session) {
      session.stopRunningStream()
    }
  }, [session])

  const stopAndTruncate = useCallback<UseAiChatResult['stopAndTruncate']>(
    (messageId, length) => {
      console.log('[useAiChatSession] stopAndTruncate called', { messageId, length, hasSession: !!session })
      if (session) {
        session.stopAndTruncate(messageId, length)
      }
    },
    [session],
  )

  const resetError = useCallback<UseAiChatResult['resetError']>(() => {
    setError(null)
  }, [])

  const getRecentMessagesForDigest = useCallback<UseAiChatResult['getRecentMessagesForDigest']>(
    (limit: number) => {
      const messages = state?.viewMessages ?? []
      const visible = messages.filter((m) => !m.hidden)
      if (limit <= 0 || visible.length <= limit) return visible
      return visible.slice(-limit)
    },
    [state],
  )

  return {
    loading: isGenerating,
    state,
    systemPromptInfo,
    providerType,
    error,
    send,
    sendMessage,
    sendVisionTask,
    stop,
    stopAndTruncate,
    changeRole,
    changeModel,
    resetError,
    availableModels: rawModels,
    activeModelId,
    pendingAttachments,
    uploadFiles,
    removeAttachment,
    isUploading: uploadingCount > 0,
    getRecentMessagesForDigest,
  }
}

import usageDocs from '../../docs/使用说明.md?raw'
import type { IAiClient } from '../ai/client'
import type { ChatEntryMode, EntryContext } from '../ai/domain/chatSession'
import { docConversationService } from '../ai/application/docConversationService'
import { getDirKeyFromDocPath } from '../ai/domain/docPathUtils'

export type AppCommand = () => void | Promise<void>

export type CommandRegistry = Record<string, AppCommand>

// ===== 命令上下文拆分（ISP） =====

type StatusContext = {
  setStatusMessage: (msg: string) => void
}

/**
 * 布局相关命令所需的上下文。
 */
export type LayoutCommandContext = StatusContext & {
  layout: string
  setLayout: (layout: string) => void
  setShowPreview: (value: boolean | ((prev: boolean) => boolean)) => void
  aiChatMode: 'floating' | 'docked'
  setAiChatMode: (mode: 'floating' | 'docked') => void
  aiChatDockSide: 'left' | 'right'
  setAiChatDockSide: (side: 'left' | 'right') => void
  aiChatOpen: boolean
}

/**
 * 文件/标签相关命令所需的上下文。
 */
export type FileCommandContext = StatusContext & {
  confirmLoseChanges: () => boolean
  /**
   * 是否存在需要用户确认的未保存变更
   */
  hasUnsavedChanges: () => boolean
  newDocument: () => void
  setFilePath: (path: string) => void
  applyOpenedContent: (content: string) => void
  openFile: () => Promise<any>
  save: () => Promise<any>
  saveAs: () => Promise<any>
  handleShowRecent?: () => Promise<void>
  clearRecentAll: () => Promise<any>
  createTab: (opts?: { title?: string; path?: string; content?: string }) => void
  updateActiveMeta: (path: string, dirty: boolean) => void
  openFolderInSidebar?: () => Promise<void>
  /** 打开文件后，向 Sidebar 注入一个独立文件条目 */
  addStandaloneFile?: (path: string) => void
  /** 当通过命令系统打开 PDF 时，通知 WorkspaceShell 刷新 PDF 最近列表 */
  refreshPdfRecent?: () => Promise<void> | void
  /** 导出命令 */
  exportHtml?: () => Promise<void>
  exportPdf?: () => Promise<void>
}

/**
 * 应用生命周期相关命令（关闭标签、退出应用）所需的上下文。
 */
export type AppLifecycleCommandContext = StatusContext & {
  confirmLoseChanges: () => boolean
  toggleSidebarVisible?: () => void
  closeCurrentTab: () => void
  onRequestCloseCurrentTab?: () => void
  onRequestQuit?: () => void
}

/**
 * 帮助/文档相关命令所需的上下文。
 */
export type HelpCommandContext = StatusContext & {
  confirmLoseChanges: () => boolean
  newDocument: () => void
  applyOpenedContent: (content: string) => void
  setFilePath: (path: string) => void
  /** 打开关于对话框的回调，由 WorkspaceShell 提供 */
  openAboutDialog?: () => void
}

/**
 * AI 相关命令所需的上下文。
 */
export type AiCommandContext = StatusContext & {
  aiClient?: IAiClient
  /**
   * 打开 AI Chat 对话框的 UI 回调，由 WorkspaceShell 提供。
   */
  openAiChatDialog?: (options: { entryMode: ChatEntryMode; initialContext?: EntryContext }) => void
  /** 打开 Global Memory 对话框的 UI 回调，由 WorkspaceShell 提供。 */
  openGlobalMemoryDialog?: (options: { initialTab: 'persona' | 'manage' }) => void
  /** 获取当前编辑器中的完整 Markdown 文本 */
  getCurrentMarkdown?: () => string
  /** 获取当前标签对应的文件名（用于展示给模型） */
  getCurrentFileName?: () => string | null
  /** 获取当前编辑器中选中的文本内容 */
  getCurrentSelectionText?: () => string | null
  /** 获取当前文档的完整路径（用于文档会话历史/清理/压缩） */
  getCurrentFilePath?: () => string | null
  /** 打开文档会话历史视图（由 WorkspaceShell 提供，当前版本可选） */
  openDocConversationsHistory?: (docPath: string) => void
  /** 以下字段来自 Help/File 上下文，在 CommandContext 中总是存在，这里标记为可选以便 AI 命令复用 */
  newDocument?: () => void
  applyOpenedContent?: (content: string) => void
  setFilePath?: (path: string) => void
}

/**
 * 完整的命令上下文：各子上下文的并集。
 * 外层系统（如 useCommandSystem）只需要提供这一份，总体仍保持向后兼容。
 */
export type CommandContext = LayoutCommandContext &
  FileCommandContext &
  AppLifecycleCommandContext &
  HelpCommandContext &
  AiCommandContext

// ===== 分组命令工厂 =====

let lastLayoutForPreviewOnly: string | null = null

function createLayoutCommands(ctx: LayoutCommandContext): CommandRegistry {
  return {
    layout_preview_left: () => {
      ctx.setLayout('preview-left')
      ctx.setShowPreview(true)
      ctx.setStatusMessage('布局：预览在左')
    },
    layout_preview_right: () => {
      ctx.setLayout('preview-right')
      ctx.setShowPreview(true)
      ctx.setStatusMessage('布局：预览在右')
    },
    layout_editor_only: () => {
      ctx.setLayout('editor-only')
      ctx.setShowPreview(false)
      ctx.setStatusMessage('布局：仅编辑器')
    },
    layout_preview_only: () => {
      ctx.setLayout('preview-only')
      ctx.setShowPreview(true)
      ctx.setStatusMessage('布局：仅预览')
    },
    toggle_preview_only: () => {
      if (ctx.layout === 'preview-only') {
