        return false
    }
}

/**
 * 通过主窗口 Portal 唤起打印，这种方式在 macOS/Tauri 下稳定性最高
 */
async function printViaMainPortal(html: string, title: string): Promise<void> {
    // 1. 清理旧环境
    const cleanupOld = () => {
        const ids = ['haomd-print-portal', 'haomd-print-override', 'haomd-print-assets']
        ids.forEach(id => {
            const el = document.getElementById(id)
            if (el) el.parentNode?.removeChild(el)
        })
    }
    cleanupOld()

    const originalTitle = document.title
    document.title = title

    // 2. 解析 HTML
    const parser = new DOMParser()
    const doc = parser.parseFromString(html, 'text/html')
    const bodyContent = doc.body.innerHTML
    const styleAssets = Array.from(doc.head.querySelectorAll('style, link')).map(el => el.outerHTML).join('\n')
    const scriptTags = Array.from(doc.head.querySelectorAll('script'))

    // 3. 注入 Portal 和 样式
    const portal = document.createElement('div')
    portal.id = 'haomd-print-portal'
    portal.innerHTML = `<div class="markdown-body">${bodyContent}</div>`
    document.body.appendChild(portal)

    const assetContainer = document.createElement('div')
    assetContainer.id = 'haomd-print-assets'
    assetContainer.innerHTML = styleAssets
    document.head.appendChild(assetContainer)

    const style = document.createElement('style')
    style.id = 'haomd-print-override'
    style.innerHTML = `
        /* 离屏渲染策略：保持显示以便 Mermaid 计算尺寸，但移出用户视线 */
        #haomd-print-portal { 
            position: fixed !important;
            left: -9999px !important;
            top: 0 !important;
            display: block !important;
            visibility: visible !important;
            width: 1000px !important; /* 给定固定宽度，防止图表因尺寸不确定而折叠 */
            background: white !important;
        }

        @media print {
            body { 
                visibility: hidden !important; 
                background: white !important; 
                margin: 0 !important; 
            }
            #haomd-print-portal {
                visibility: visible !important; 
                display: block !important;
                position: absolute !important; 
                left: 0 !important; 
                top: 0 !important;
                width: 100% !important; 
                height: auto !important;
                background: white !important; 
                z-index: 2147483647 !important;
                color: #1a1a1a !important;
            }
            #root, #app, .workspace-shell { display: none !important; }
            .markdown-body { 
                max-width: none !important; 
                background: white !important; 
                color: #1a1a1a !important; 
                font-size: 12pt !important; 
            }
            .markdown-body code { background-color: rgba(27, 31, 35, 0.05) !important; color: #24292e !important; text-shadow: none !important; }
            .markdown-body pre { background-color: #f6f8fa !important; border: 1px solid #dfe2e5 !important; white-space: pre-wrap !important; }
            @page { margin: 1.5cm; }
            * { -webkit-print-color-adjust: exact !important; print-color-adjust: exact !important; }
        }
    `
    document.head.appendChild(style)

    // 4. 动态注入并等待脚本加载 (Mermaid 等)
    const scriptList: HTMLScriptElement[] = []
    const scriptPromises = scriptTags.map(oldScript => {
        return new Promise<void>((resolve) => {
            const newScript = document.createElement('script')
            Array.from(oldScript.attributes).forEach(attr => newScript.setAttribute(attr.name, attr.value))
            if (oldScript.innerHTML) newScript.innerHTML = oldScript.innerHTML

            if (newScript.src) {
                newScript.onload = () => resolve()
                newScript.onerror = () => resolve()
            } else {
                // 内联脚本
                setTimeout(resolve, 10)
            }
            document.head.appendChild(newScript)
            scriptList.push(newScript)
        })
    })

    await Promise.all(scriptPromises)

    // 5. 触发 Mermaid 渲染
    // 增加轮询等待 Mermaid 对象挂载到 window
    const waitForMermaid = async () => {
        for (let i = 0; i < 20; i++) {
            if ((window as any).mermaid) return true
            await new Promise(r => setTimeout(r, 100))
        }
        return false
    }

    if (await waitForMermaid()) {
        const win = window as any
        console.log('[Print] 启动 Mermaid 渲染...')
        try {
            win.mermaid.initialize({ startOnLoad: false, theme: 'default' })
            await win.mermaid.run({
                querySelector: '#haomd-print-portal .mermaid'
            })
        } catch (e) {
            console.error('[Print] Mermaid 渲染失败:', e)
        }
    }

    // 6. 唤起打印
    console.log('[Print] 准备唤起打印预览...')
    return new Promise((resolve) => {
        const cleanup = () => {
            setTimeout(() => {
                cleanupOld()
                scriptList.forEach(s => s.parentNode?.removeChild(s))
                document.title = originalTitle
                resolve()
            }, 5000)
        }
        window.onafterprint = cleanup

        setTimeout(() => {
            try {
                window.print()
            } catch (e) {
                console.error('[Print] 打印指令执行失败:', e)
                cleanup()
            }
        }, 800) // 给 SVG 渲染留出最后的时间
    })
}

import { invoke } from '@tauri-apps/api/core'
import type { ImageSource } from '../ai/domain/types'
import type { IImageUrlResolver } from './imageUrlResolver'

async function imagePathToDataUrl(path: string): Promise<string> {
  // 约定 Rust 侧提供 read_image_as_data_url 命令，返回 { data_url: string }
  const result = await invoke<{ data_url: string }>('read_image_as_data_url', { path })
  return result.data_url
}

/**
 * 默认图片 URL 解析器：
 * - url:      直接返回原字符串
 * - data_url: 直接返回原字符串
 * - path:     调用 Tauri 后端读取本地文件并转为 data URL
 */
export const defaultImageUrlResolver: IImageUrlResolver = {
  async resolve(source: ImageSource): Promise<string> {
    switch (source.kind) {
      case 'url':
        return source.url
      case 'data_url':
        return source.dataUrl
      case 'path':
        return await imagePathToDataUrl(source.path)
      default:
        throw new Error(`Unsupported ImageSource kind: ${(source as any).kind}`)
    }
  },
}

// rehype 插件：给 KaTeX 根元素补充 data-line-start / data-line-end 属性
// 设计目标：
// - 只处理 className 包含 katex-display / katex 的元素
// - 仅当节点存在 position.start.line 时才写入行号
// - 不覆盖已有的 data-line-* 属性，避免与其它插件冲突

export function rehypeMathLineAnchors() {
  return function attach(tree: any) {
    // 递归遍历树，允许子节点继承父节点的位置信息
    const visit = (node: any, inheritedPos?: any): void => {
      if (!node || typeof node !== 'object') return

      // 优先使用节点自身的 position，其次继承父节点的 position
      const pos = (node as any).position || inheritedPos

      // 只关心 element 节点
      if (node.type === 'element') {
        const props = node.properties || {}
        const className = props.className

        if (className) {
          const classes = Array.isArray(className)
            ? className
            : String(className).split(/\s+/)

          const isKatexDisplay = classes.includes('katex-display')
          const isKatexInline = classes.includes('katex') && !classes.includes('katex-display')

          if (isKatexDisplay || isKatexInline) {
            const startLine = pos?.start?.line
            const endLine = pos?.end?.line ?? startLine

            if (typeof console !== 'undefined') {
              console.log('[rehypeMathLineAnchors] class=%o pos=%o start=%s end=%s props(before)=%o', classes, pos, startLine, endLine, props)
            }

            if (typeof startLine === 'number') {
              if (!node.properties) node.properties = props

              if (node.properties['data-line-start'] == null) {
                node.properties['data-line-start'] = String(startLine)
              }
              if (endLine != null && node.properties['data-line-end'] == null) {
                node.properties['data-line-end'] = String(endLine)
              }

              if (typeof console !== 'undefined') {
                console.log('[rehypeMathLineAnchors] props(after)=%o', node.properties)
              }
            }
          }
        }
      }

      const children = (node as any).children
      if (Array.isArray(children)) {
        for (const child of children) visit(child, pos)
      }
    }

    visit(tree)
  }
}

import { useEffect, useRef } from 'react'
import type { PDFDocumentProxy } from '../hooks/usePdfDocument'
import * as pdfjsLib from 'pdfjs-dist'

export interface PdfTextLayerProps {
  pdfDocument: PDFDocumentProxy
  pageNumber: number
  scale: number
}

/**
 * 文本层：叠加在 canvas 之上的真实 DOM 文本，用于选择/复制/后续批注。
 *
 * 不使用 pdf.js 自带的 textLayerBuilder，而是：
 * 1）getTextContent() 拿到每个文字片段；
 * 2）用 Util.transform 计算在页面坐标系中的位置；
 * 3）按“行”合并片段，每行只生成一个 span，避免选区叠成很多条纹。
 */
export function PdfTextLayer({ pdfDocument, pageNumber, scale }: PdfTextLayerProps) {
  const layerRef = useRef<HTMLDivElement | null>(null)

  useEffect(() => {
    const container = layerRef.current
    if (!container || !pdfDocument) return

    let cancelled = false
    container.innerHTML = ''

    const render = async () => {
      try {
        const page = await pdfDocument.getPage(pageNumber)
        if (cancelled) return

        const viewport = page.getViewport({ scale })
        const textContent = await page.getTextContent()
        if (cancelled) return

        const Util = (pdfjsLib as any).Util
        const items: any[] = (textContent.items || []) as any[]

        type Fragment = { text: string; x: number; yTop: number; fontSize: number }
        const fragments: Fragment[] = []

        for (const item of items) {
          const str: string = item.str || ''
          if (!str) continue

          let x = 0
          let yTop = 0
          let fontSize = 1

          try {
            if (Util && item.transform) {
              const tx = Util.transform(viewport.transform, item.transform)
              const c = tx[2]
              const d = tx[3]
              const e = tx[4]
              const f = tx[5]
              const fontHeight = Math.hypot(c, d) || Math.abs(d) || 1

              x = e
              yTop = f - fontHeight
              fontSize = fontHeight
            }
          } catch (e) {
            console.warn('[PdfTextLayer] failed to compute transform for text item', e)
          }

          fragments.push({ text: str, x, yTop, fontSize })
        }

        if (fragments.length === 0) return

        // 按行聚合：同一行的 yTop 足够接近就认为是一行
        type Line = { yTop: number; fontSize: number; frags: Fragment[] }
        const lines: Line[] = []

        const lineThreshold = 1 // 垂直合并阈值（像素）

        for (const frag of fragments) {
          let line = lines.find((l) => Math.abs(l.yTop - frag.yTop) <= lineThreshold)
          if (!line) {
            line = { yTop: frag.yTop, fontSize: frag.fontSize, frags: [] }
            lines.push(line)
          }
          line.frags.push(frag)
        }

        // 生成 DOM：每行一个 span，按 x 从左到右拼接文本
        for (const line of lines) {
          line.frags.sort((a, b) => a.x - b.x)

          const span = document.createElement('span')
          span.textContent = line.frags.map((f) => f.text).join('')
          span.style.position = 'absolute'
          span.style.whiteSpace = 'pre'

          const minX = line.frags[0]?.x ?? 0
          span.style.left = `${minX}px`
          span.style.top = `${line.yTop}px`
          span.style.fontSize = `${line.fontSize}px`

          // 文字本身几乎透明，只依赖 selection 背景
          span.style.color = 'rgba(0, 0, 0, 0.02)'

          container.appendChild(span)
        }
      } catch (e) {
        if (!cancelled) {
          console.error('[PdfTextLayer] failed to render text layer', e)
        }
      }
    }

    void render()

    return () => {
      cancelled = true
      if (container) {
        container.innerHTML = ''
      }
    }
  }, [pdfDocument, pageNumber, scale])

  return <div ref={layerRef} className="pdf-text-layer" />
}

import type { ReactElement } from 'react'
import { useRef, useState, useEffect } from 'react'
import type { PDFDocumentProxy } from '../hooks/usePdfDocument'
import { usePdfDocument } from '../hooks/usePdfDocument'
import { useVirtualPages } from '../hooks/useVirtualPages'
import { PdfPage } from './PdfPage'

type PdfReadingState = {
  page: number
  scale: number
}

function getPdfStateKey(filePath: string) {
  return `pdf-reading-state:${filePath}`
}

function loadPdfReadingState(filePath: string): PdfReadingState | null {
  if (typeof window === 'undefined') return null
  try {
    const key = getPdfStateKey(filePath)
    const raw = window.localStorage.getItem(key)
    if (!raw) return null
    const parsed = JSON.parse(raw) as PdfReadingState
    if (typeof parsed.page === 'number' && typeof parsed.scale === 'number') {
      return parsed
    }
    return null
  } catch {
    return null
  }
}

function savePdfReadingState(filePath: string, state: PdfReadingState) {
  if (typeof window === 'undefined') return
  try {
    const key = getPdfStateKey(filePath)
    window.localStorage.setItem(key, JSON.stringify(state))
  } catch {
    // ignore
  }
}

export interface PdfViewerProps {
  filePath: string
  onClose?: () => void
  /** 向父组件注册一个用于获取当前 PDF 文本选区的 getter */
  onRegisterSelectionGetter?: (getter: (() => string | null) | null) => void
}

export function PdfViewer({ filePath, onRegisterSelectionGetter }: PdfViewerProps) {
  const containerRef = useRef<HTMLDivElement | null>(null)
  const [scale, setScale] = useState(1.25)
  const { pdfDocument, pageCount, loading, error } = usePdfDocument(filePath)
  const [currentPage, setCurrentPage] = useState(1)
  const [pageInput, setPageInput] = useState('1')
  const [basePageWidth, setBasePageWidth] = useState<number | null>(null)
  const [basePageHeight, setBasePageHeight] = useState<number | null>(null)

  const ZOOM_MIN = 0.5
  const ZOOM_MAX = 3
  const ZOOM_STEP = 0.25
  const zoomPercent = Math.round(scale * 100)

  const scrollToPageWithScale = (page: number, scaleForScroll: number) => {
    const el = containerRef.current
    if (!el) return

    const baseHeight = basePageHeight ?? 800
    const estimatedPageHeight = Math.max(1, baseHeight * scaleForScroll)
    el.scrollTop = (page - 1) * estimatedPageHeight
  }

  const handleZoomIn = () => {
    setScale((prev) => {
      const next = Math.min(ZOOM_MAX, prev + ZOOM_STEP)
      scrollToPageWithScale(currentPage, next)
      return next
    })
  }

  const handleZoomOut = () => {
    setScale((prev) => {
      const next = Math.max(ZOOM_MIN, prev - ZOOM_STEP)
      scrollToPageWithScale(currentPage, next)
      return next
    })
  }

  const handleZoomReset = () => {
    const next = 1.0
    setScale(next)
    scrollToPageWithScale(currentPage, next)
  }

  const handleZoomFitWidth = () => {
    const el = containerRef.current
    if (!el || !basePageWidth) return

    // 可用内容宽度：减去左右 padding（与 .pdf-scroll-container 的 16px 对应）
    const horizontalPadding = 32
    const availableWidth = el.clientWidth - horizontalPadding
    if (availableWidth <= 0) return

    const fitScale = availableWidth / basePageWidth
    const clamped = Math.min(ZOOM_MAX, Math.max(ZOOM_MIN, fitScale))

    setScale(clamped)
    scrollToPageWithScale(currentPage, clamped)
  }

  // 当文档或总页数变化时，确保当前页在合法范围内
  useEffect(() => {
    if (!pageCount || pageCount <= 0) {
      setCurrentPage(1)
      setPageInput('1')
      return
    }
    if (currentPage > pageCount) {
      setCurrentPage(pageCount)
      setPageInput(String(pageCount))
    }
  }, [pageCount, currentPage])

  // 文档加载完成后：优先从 localStorage 恢复阅读状态；若无记录，则默认“适配宽度”
  useEffect(() => {
    if (!pdfDocument || !pageCount || pageCount <= 0) return

    const saved = loadPdfReadingState(filePath)
    const el = containerRef.current

    if (saved) {
      const clampedPage = Math.min(Math.max(saved.page, 1), pageCount)
      const clampedScale = Math.min(ZOOM_MAX, Math.max(ZOOM_MIN, saved.scale))

      setScale(clampedScale)
      setCurrentPage(clampedPage)
      setPageInput(String(clampedPage))

      if (el) {
        const estimatedPageHeight = Math.max(1, (basePageHeight ?? 800) * clampedScale)
        el.scrollTop = (clampedPage - 1) * estimatedPageHeight
      }
      return
    }

    // 没有历史记录时：自动计算“适配宽度”的缩放比例
    if (!el || !basePageWidth) return

    const horizontalPadding = 32
    const availableWidth = el.clientWidth - horizontalPadding
    if (availableWidth <= 0) return

    const fitScale = availableWidth / basePageWidth
    const clampedFit = Math.min(ZOOM_MAX, Math.max(ZOOM_MIN, fitScale))

    setScale(clampedFit)
    setCurrentPage(1)
    setPageInput('1')
    el.scrollTop = 0
  }, [pdfDocument, pageCount, filePath, basePageHeight, basePageWidth])

  // 当页码或缩放发生变化时，将当前阅读状态持久化到 localStorage
  useEffect(() => {
    if (!pageCount || pageCount <= 0) return

    const handle = window.setTimeout(() => {
      savePdfReadingState(filePath, {
        page: currentPage,
        scale,
      })
    }, 300)

    return () => {
      window.clearTimeout(handle)
    }
  }, [filePath, currentPage, scale, pageCount])

  // 计算 PDF 原始尺寸（scale = 1 时的宽高），用于“适配宽度”缩放和多页高度估算
  useEffect(() => {
    let cancelled = false
    ;(async () => {
      if (!pdfDocument) return
      try {
        const page = await (pdfDocument as PDFDocumentProxy).getPage(1)
        if (cancelled) return
        const viewport = page.getViewport({ scale: 1 })
        setBasePageWidth(viewport.width)
        setBasePageHeight(viewport.height)
      } catch (e) {
        console.error('[PdfViewer] failed to compute base page size', e)
      }
    })()
    return () => {
      cancelled = true
    }
  }, [pdfDocument])

  const goToPage = (page: number, estimatedPageHeight?: number) => {
    if (!pageCount || pageCount <= 0) return
    const clamped = Math.min(Math.max(page, 1), pageCount)
    setCurrentPage(clamped)
    setPageInput(String(clamped))

    const el = containerRef.current
    if (el && estimatedPageHeight && estimatedPageHeight > 0) {
      // 多页模式下，根据估算高度滚动到对应页的大致位置
      el.scrollTop = (clamped - 1) * estimatedPageHeight
    } else if (el) {
      // 兜底：单页模式或高度未知时，仍然滚动到顶部
      el.scrollTop = 0
    }
  }

  const handlePrev = () => {
    goToPage(currentPage - 1, pageHeightForVirtual)
  }

  const handleNext = () => {
    goToPage(currentPage + 1, pageHeightForVirtual)
  }

  const handlePageInputChange: React.ChangeEventHandler<HTMLInputElement> = (e) => {
    setPageInput(e.target.value.replace(/[^0-9]/g, ''))
  }

  const handlePageInputCommit = () => {
    if (!pageInput) {
      setPageInput(String(currentPage))
      return
    }
    const num = Number(pageInput)
    if (!Number.isFinite(num) || num <= 0) {
      setPageInput(String(currentPage))
      return
    }
    goToPage(num, pageHeightForVirtual)
  }

  const handlePageInputBlur = () => {
    handlePageInputCommit()
  }

  const handlePageInputKeyDown: React.KeyboardEventHandler<HTMLInputElement> = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault()
      handlePageInputCommit()
    }
  }

  // 估算单页高度（基于首屏 viewport 高度和当前 scale），供多页虚拟滚动使用
  const pageHeightForVirtual = Math.max(1, (basePageHeight ?? 800) * scale)

  // 实时读取当前 PDF 文本选区（仅限 pdf-scroll-container 内部）
  const getCurrentSelectionText = () => {
    if (typeof window === 'undefined') return null
    const sel = window.getSelection()
    if (!sel || sel.isCollapsed) return null

    const container = containerRef.current
    if (!container) return null

    const isInContainer = (node: Node | null) => !!node && container.contains(node)
    const anchorNode = sel.anchorNode
    const focusNode = sel.focusNode
    if (!isInContainer(anchorNode) && !isInContainer(focusNode)) return null

    const text = sel.toString().trim()
    return text || null
  }

  // 将选区 getter 注册给父组件，在组件卸载时清理
  useEffect(() => {
    if (!onRegisterSelectionGetter) return

    onRegisterSelectionGetter(() => getCurrentSelectionText())
    return () => {
      onRegisterSelectionGetter(null)
    }
  }, [onRegisterSelectionGetter, filePath, basePageHeight, scale])

  const { nearbyRange, totalHeight, onScroll: handleVirtualScroll } = useVirtualPages({
    pageCount,
    pageHeight: pageHeightForVirtual,
    containerRef,
    bufferPages: 2,
  })

  const handleScroll: React.UIEventHandler<HTMLDivElement> = (e) => {
    handleVirtualScroll()

    const container = e.currentTarget
    if (!pageCount || pageHeightForVirtual <= 0) return

    const scrollTop = container.scrollTop
    const approxIndex = Math.round(scrollTop / pageHeightForVirtual)
    const nextPage = Math.min(pageCount, Math.max(1, approxIndex + 1))

    if (nextPage !== currentPage) {
      setCurrentPage(nextPage)
      setPageInput(String(nextPage))
    }
  }

  const pages: ReactElement[] = []
  const startIndex = nearbyRange.start
  const endIndex = nearbyRange.end

  if (pdfDocument && pageCount > 0) {
    for (let index = startIndex; index < endIndex; index += 1) {
      const pageNumber = index + 1
      if (pageNumber > pageCount) break

      pages.push(
        <div
          key={pageNumber}
          style={{
            position: 'absolute',
            top: index * pageHeightForVirtual,
            left: 0,
            right: 0,
            display: 'flex',
            justifyContent: 'center',
          }}
        >
          <PdfPage pdfDocument={pdfDocument as PDFDocumentProxy} pageNumber={pageNumber} scale={scale} />
        </div>,
      )
    }
  }

  if (loading) {
    return <div className="pdf-viewer">正在加载 PDF…</div>
  }

  if (error) {
    return <div className="pdf-viewer">{error}</div>
  }

  if (!pdfDocument || pageCount === 0) {
    return <div className="pdf-viewer">未加载 PDF 文档</div>
  }

  return (
    <div className="pdf-viewer">
      <div className="pdf-viewer-main">
        <div
          ref={containerRef}
          className="pdf-scroll-container"
          onScroll={handleScroll}
        >
          <div
            style={{
              position: 'relative',
              height: totalHeight || pageHeightForVirtual,
            }}
          >
            {pages}
          </div>
        </div>
      </div>
      <div className="pdf-viewer-sidebar">
        <div className="pdf-toolbar">
          <div className="pdf-toolbar-section pdf-toolbar-pages">
            <div className="pdf-page-current-wrapper">
              <input
                type="text"
                className="pdf-page-input-pill"
                value={pageInput}
                onChange={handlePageInputChange}
                onBlur={handlePageInputBlur}
                onKeyDown={handlePageInputKeyDown}
                inputMode="numeric"
              />
            </div>
            <div className="pdf-page-total-text">{pageCount}</div>
            <button
              type="button"
              className="pdf-icon-btn"
              onClick={handlePrev}
              disabled={currentPage <= 1}
              aria-label="上一页"
            >
              ▲
            </button>
            <button
              type="button"
              className="pdf-icon-btn"
              onClick={handleNext}
              disabled={currentPage >= pageCount}
              aria-label="下一页"
            >
              ▼
            </button>
          </div>

          <div className="pdf-toolbar-separator" />

          <div className="pdf-toolbar-section pdf-toolbar-zoom">
            <button
              type="button"
              className="pdf-icon-btn pdf-icon-btn--zoom-reset"
              onClick={handleZoomReset}
              disabled={Math.abs(scale - 1) < 0.001}
              aria-label="恢复实际大小"
            >
              <span className="pdf-icon-glyph" aria-hidden="true" />
            </button>
            <button
              type="button"
              className="pdf-icon-btn"
              onClick={handleZoomFitWidth}
              disabled={!basePageWidth}
              aria-label="适配宽度"
            >
              ⤢
            </button>
            <div className="pdf-zoom-percent">{zoomPercent}%</div>
            <div className="pdf-zoom-icon-row">
              <button
                type="button"
                className="pdf-icon-btn"
                onClick={handleZoomIn}
                disabled={scale >= ZOOM_MAX}
                aria-label="放大"
              >
                +
              </button>
              <button
                type="button"
                className="pdf-icon-btn"
                onClick={handleZoomOut}
                disabled={scale <= ZOOM_MIN}
                aria-label="缩小"
              >
                -
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import * as pdfjsLib from 'pdfjs-dist'
import pdfWorker from 'pdfjs-dist/build/pdf.worker?worker&url'
import { invoke } from '@tauri-apps/api/core'
import { isTauriEnv } from '../../platform/runtime'
import type { BackendResult } from '../../platform/backendTypes'

// 配置 PDF.js worker，避免在部分环境下因找不到默认 worker 而报错
;(pdfjsLib as any).GlobalWorkerOptions.workerSrc = pdfWorker

const isTauri = isTauriEnv

// 在这里用 any 代替具体类型，避免对 pdfjs 内部类型路径的强依赖
export type PDFDocumentProxy = any

export function usePdfDocument(filePath: string | null) {
  const [pdfDocument, setPdfDocument] = useState<PDFDocumentProxy | null>(null)
  const [pageCount, setPageCount] = useState(0)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState<string | null>(null)

  useEffect(() => {
    let cancelled = false

    const load = async () => {
      if (!filePath) {
        setPdfDocument(null)
        setPageCount(0)
        setError(null)
        return
      }

      setLoading(true)
      setError(null)

      try {
        let loadingTask: any

        if (isTauri && isTauri()) {
          const resp = await invoke<BackendResult<number[]>>('read_binary_file', { path: filePath })
          if ('Err' in resp) {
            console.error('[usePdfDocument] read_binary_file failed', resp.Err.error)
            throw new Error(resp.Err.error.message)
          }
          const bytes = new Uint8Array(resp.Ok.data)
          loadingTask = pdfjsLib.getDocument({ data: bytes })
        } else {
          // 浏览器环境：期望 filePath 是可访问的 URL
          loadingTask = pdfjsLib.getDocument({ url: filePath })
        }

        const doc = await loadingTask.promise
        if (cancelled) return
        setPdfDocument(doc)
        setPageCount(doc.numPages ?? 0)
      } catch (e) {
        if (cancelled) return
        console.error('[usePdfDocument] failed to load pdf', { filePath, error: e })
        setError('Failed to load PDF')
        setPdfDocument(null)
        setPageCount(0)
      } finally {
        if (!cancelled) setLoading(false)
      }
    }

    void load()

    return () => {
      cancelled = true
    }
  }, [filePath])

  return { pdfDocument, pageCount, loading, error }
}

import { invoke } from '@tauri-apps/api/core'
import type { BackendResult } from '../platform/backendTypes'
import type { RecentFile } from '../files/types'

// 与后端 PdfRecentEntry 对应的类型
interface BackendPdfRecentEntry {
  path: string
  display_name: string
  last_opened_at: number
  folder_id?: string | null
}

export interface PdfFolder {
  id: string
  name: string
}

/**
 * 列出 PDF 最近文件列表。
 *
 * - 数据来源：后端 pdf_recent.json
 * - 返回值：已经映射为前端的 RecentFile 结构，isFolder 恒为 false
 */
export async function listPdfRecent(limit?: number): Promise<RecentFile[]> {
  const args: Record<string, unknown> = {}
  if (typeof limit === 'number') {
    args.limit = limit
  }

  const resp = await invoke<BackendResult<BackendPdfRecentEntry[]>>('list_pdf_recent', args)

  if ('Ok' in resp) {
    const items = resp.Ok.data
    return items.map<RecentFile>((item) => ({
      path: item.path,
      displayName: item.display_name,
      lastOpenedAt: item.last_opened_at,
      isFolder: false,
      // 前端 RecentFile 增加可选 folderId，未分类为 undefined
      folderId: item.folder_id ?? undefined,
    }))
  }

  const { error } = resp.Err
  const err: any = new Error(error.message)
  err.code = error.code
  err.traceId = error.trace_id
  throw err
}

/**
 * 记录单个 PDF 文件到 pdf_recent.json。
 *
 * - 不关心返回值，仅确保命令被正确触发。
 */
export async function logPdfRecent(path: string): Promise<void> {
  await invoke('log_pdf_recent_file', { path })
}

/**
 * 从 pdf_recent.json 中删除指定 PDF 记录。
 */
export async function deletePdfRecent(path: string): Promise<void> {
  await invoke('delete_pdf_recent_entry', { path })
}

/**
 * 加载 PDF 虚拟文件夹列表。
 */
export async function loadPdfFolders(): Promise<PdfFolder[]> {
  const resp = await invoke<BackendResult<PdfFolder[]>>('load_pdf_folders', {})

  if ('Ok' in resp) {
    const items = resp.Ok.data ?? []
    // 按名称本地化排序
    return [...items].sort((a, b) => a.name.localeCompare(b.name))
  }

  const { error } = resp.Err
  const err = new Error(error.message) as Error & { code?: string; traceId?: string }
  err.code = error.code
  err.traceId = error.trace_id
  throw err
}

/**
 * 保存 PDF 虚拟文件夹列表。
 */
export async function savePdfFolders(folders: PdfFolder[]): Promise<void> {
  await invoke('save_pdf_folders', { folders })
}

/**
 * 更新单个 PDF 的虚拟文件夹归属。
 *
 * @param path     PDF 路径
 * @param folderId 目标虚拟文件夹 id，传 null 表示移回根列表
 */
export async function updatePdfRecentFolder(path: string, folderId: string | null): Promise<void> {
  await invoke('update_pdf_recent_folder', { path, folderId })
}
